INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNL_2021_consolidated', 'VNL', 2021, 'consolidated', 'Công ty có nhiều giao dịch thương mại với các công ty liên kết và liên doanh trong mạng lưới logistics, với tổng doanh thu cung cấp dịch vụ cho bên liên quan là 815 triệu VND và chi phí nhận dịch vụ từ bên liên quan là 1,264 triệu VND. Giá dịch vụ theo thỏa thuận, không có dấu hiệu giao dịch bất thường hay giá chuyển nhượng sai lệch lớn. Tuy nhiên, khoản đầu tư vào Công ty Cổ phần Logistics Kim Thành đã phải trích lập dự phòng 3.1 tỷ VND cho thấy rủi ro.', 'Công ty không có nợ vay ngân hàng/tổ chức tín dụng lớn. Nợ chủ yếu là phải trả người bán thương mại (100.7 tỷ VND ngắn hạn) và các khoản phải trả khác. Đáng lưu ý là khoản tạm ứng 32.8 tỷ VND cho Công ty Cổ phần Đường Khánh Hội liên quan đến dự án tại 145-147 Nguyễn Tất Thành vẫn chưa được thanh lý do chờ quyết định của UBND TP.HCM, tạo rủi ro về dòng tiền.', 'Công ty hoạt động trong lĩnh vực logistics, không có hàng tồn kho vật lý (nguyên vật liệu, thành phẩm) hay dự án xây dựng dở dang. Rủi ro tồn kho không áp dụng cho doanh nghiệp này.', 4, 'Công ty Cổ phần Logistics Vinalink đạt kết quả kinh doanh ấn tượng năm 2021 với doanh thu tăng 22.7% lên 1,464 tỷ VND và lợi nhuận sau thuế tăng 87.1% lên 37.7 tỷ VND, chủ yếu nhờ đại dịch COVID-19 thúc đẩy nhu cầu vận chuyển quốc tế và giá cước tăng cao. Biên lợi nhuận gộp 3.89% phản ánh đặc thù ngành logistics. Công ty có bảng cân đối lành mạnh với tỷ lệ nợ/vốn chủ sở hữu thấp, dòng tiền hoạt động kinh doanh dương. Cổ tức đều đặn 1,500 VND/cổ phiếu/năm. Các rủi ro chính bao gồm: khoản đầu tư vào Logistics Kim Thành có dự phòng lớn, khoản tạm ứng 32.8 tỷ VND chưa thu hồi, và triển vọng phụ thuộc vào diễn biến dịch COVID-19.'),
('VNL_2015_consolidated', 'VNL', 2015, 'consolidated', 'Doanh nghiệp có giao dịch với nhiều bên liên quan bao gồm công ty con, liên doanh, liên kết và thành viên quản lý. Giao dịch bao gồm cung cấp dịch vụ và cho vay. Cần lưu ý mức lãi suất áp dụng cho khoản cho vay 30 tỷ VNĐ không được tiết lộ, có thể tiềm ẩn rủi ro về giao dịch không công bằng.', 'Nợ phải trả chủ yếu là nợ thương mại và khoản tạm ứng, không có nợ vay ngân hàng chi tiết. Áp lực nợ vay không cao, tài sản thế chấp không được đề cập.', 'Doanh nghiệp không có hàng tồn kho. Có một số dự án bất động sản dưới dạng trả trước dài hạn, nhưng không có dấu hiệu ứ đọng.', 5, 'Doanh nghiệp có doanh thu tăng trưởng nhưng lợi nhuận giảm. Tỷ suất lợi nhuận gộp ở mức trung bình. Cơ cấu tài sản và vốn ổn định, nhưng cần theo dõi các giao dịch với bên liên quan và các dự án đầu tư.'),
('VNI_2025_consolidated', 'VNI', 2025, 'consolidated', 'Công ty có nhiều giao dịch với bên liên quan phức tạp, bao gồm cho vay không lãi suất (Công ty TNHH Tư vấn Thương mại Xây dựng điện Không Gian), mua bán căn hộ với giá trị lớn với các thành viên HĐQT và người liên quan, tạm ứng lớn cho các cá nhân. Điều này tiềm ẩn rủi ro xung đột lợi ích và quản trị yếu kém.', 'Nợ ngắn hạn vượt quá tài sản ngắn hạn 109 tỷ VND, áp lực trả nợ lớn. Nợ chủ yếu là vay cá nhân tín chấp với lãi suất cao (1-2%/tháng). Công ty không thể xác nhận số dư khoản vay và lãi vay với kiểm toán viên, cho thấy khả năng thanh toán bị hạn chế và rủi ro vỡ nợ.', 'Hàng tồn kho lớn (155 tỷ VND) chủ yếu là bất động sản (căn hộ Vinaland Tower) chưa bán được, có thể bị ứ đọng. Các dự án dở dang như Chợ Phước Long (92 tỷ VND) và Bảo Lộc (18.5 tỷ VND) có giá trị lớn, cần giám sát tiến độ và khả năng thu hồi vốn.', 8, 'Doanh nghiệp hoạt động trong lĩnh vực bất động sản, lợi nhuận giảm mạnh từ lãi sang lỗ trong năm 2025. Nợ ngắn hạn cao, áp lực tài chính lớn, có nguy cơ không hoạt động liên tục. Ban lãnh đạo có nhiều giao dịch phức tạp với công ty, tiềm ẩn rủi ro quản trị. Cần theo dõi tiến độ bán hàng, thu hồi nợ và tái cấu trúc nợ.'),
('VNI_2023_consolidated', 'VNI', 2023, 'consolidated', NULL, NULL, NULL, 5, NULL),
('VNH_2025_consolidated', 'VNH', 2025, 'consolidated', 'Công ty có giao dịch cho vay với Chủ tịch HĐQT (Ông Nguyễn Thanh Sơn) số tiền 3.320.000.000 đồng và Công ty CP Ntaco (liên quan qua ông Sơn) số tiền 3.810.000.000 đồng, không rõ lãi suất và tài sản đảm bảo. Số dư phải thu cuối kỳ với Công ty CP Ntaco là 310.000.000 đồng. Đây là các giao dịch đáng chú ý với bên liên quan, cần theo dõi chặt chẽ.', 'Công ty không có nợ vay ngân hàng, chỉ có thuế và các khoản phải nộp Nhà nước ngắn hạn là 447.891.990 đồng. Áp lực nợ vay thấp nhưng lỗ lũy kế chiếm 91,6% vốn chủ sở hữu tạo ra rủi ro tài chính nghiêm trọng.', 'Công ty không có hàng tồn kho cuối kỳ, không có dự án xây dựng dở dang hay bất động sản đầu tư. Rủi ro tồn kho không đáng kể.', 7, 'Công ty trong tình trạng tài chính yếu với lỗ lũy kế 73.526.377.517 đồng (91,6% vốn chủ sở hữu). Năm 2025, công ty có doanh thu 12.310.497.000 đồng với biên lợi nhuận gộp 7,81%, nhưng lợi nhuận chủ yếu từ hoàn nhập dự phòng phải thu khó đòi (1.922.000.000 đồng) chứ không từ hoạt động kinh doanh cốt lõi. Có nhiều giao dịch với bên liên quan (cho vay không lãi suất cho Chủ tịch HĐQT và công ty liên kết). Tiền mặt tăng từ 1,3 tỷ lên 2,9 tỷ đồng. Kiểm toán viên đưa ra ý kiến ngoại trừ về tính hiện hữu của tiền mặt và tài sản cố định. Ban lãnh đạo cam kết xúc tiến kế hoạch kinh doanh mới để cải thiện tình hình. Triển vọng đầu tư rủi ro cao do mất cân đối tài chính nghiêm trọng và thiếu bền vững trong hoạt động kinh doanh.'),
('VNI_2024_consolidated', 'VNI', 2024, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với các bên liên quan, bao gồm cho vay không lãi suất hoặc lãi suất thấp, mua bán căn hộ với ban lãnh đạo và người thân, cho thấy rủi ro về xung đột lợi ích và quản trị.', 'Nợ ngắn hạn vượt quá tài sản ngắn hạn 64.217.456.385 VND, lưu chuyển tiền tệ từ hoạt động kinh doanh âm (-11.027.390.168 VND), áp lực nợ vay lớn với lãi suất cao (1%-2%/tháng cho vay ngắn hạn), và tài sản thế chấp không rõ ràng.', 'Tồn kho chính là căn hộ hoàn thành của Dự án Vinaland Tower trị giá 219 tỷ VNĐ, có nguy cơ ứ đọng nếu thị trường bất động sản suy thoái. Các dự án xây dựng dở dang như Dự án Bảo Lộc và Dự án Chợ Phước Long có thể bị chậm tiến độ.', 8, 'Công ty có kết quả kinh doanh khả quan trong năm 2024 với lợi nhuận sau thuế 74.5 tỷ VNĐ, nhưng tình hình tài chính bất ổn với nợ ngắn hạn cao, lưu chuyển tiền tệ âm, và ý kiến kiểm toán ngoại trừ. Triển vọng đầu tư thận trọng do rủi ro về thanh toán và quản trị.'),
('VNH_2024_consolidated', 'VNH', 2024, 'consolidated', 'Công ty có giao dịch lớn với bên liên quan: cho mượn Chủ tịch HĐQT Nguyễn Thanh Sơn 3.320.000.000 đồng và Công ty Cổ phần NTACO (cũng do ông Nguyễn Thanh Sơn làm đồng Chủ tịch HĐQT) 4.120.000.000 đồng mà không rõ lãi suất và tài sản thế chấp. Đặc biệt, khoản xoá nợ phải thu 11.645.402.650 đồng cho Oceanica International được Đại hội đồng cổ đông thông qua xoá nhưng thiếu hồ sơ chứng từ hợp lệ (không có hợp đồng mua bán, hoá đơn), dấy ngờ về tính minh bạch và có nguy cơ rút tiền doanh nghiệp. Thu nhập khác từ xoá nợ 3.001.371.066 đồng cũng thiếu hồ sơ xác minh.', 'Công ty đã trả hết nợ vay ngắn hạn cá nhân 250.000.000 đồng trong năm 2024. Các khoản nợ còn lại chủ yếu là thuế phải nộp 630.185.105 đồng. Áp lực nợ vay thấp, nhưng doanh nghiệp lỗ lũy kế khổng lồ 75.710.943.108 đồng, không có dòng tiền kinh doanh, khả năng thanh toán thuế cũng đáng lo ngại.', 'Công ty không có hàng tồn kho, không có dự án xây dựng dở dang. Doanh nghiệp đã tạm dừng hoạt động kinh doanh từ năm 2024, không phát sinh doanh thu. Rủi ro tồn kho không đáng kể.', 8, 'Tình hình tài chính cực kỳ yếu kém: lỗ lũy kế 75,7 tỷ đồng, tạm dừng kinh doanh, không có doanh thu. Lợi nhuận năm 2024 (1,05 tỷ) hình thành chủ yếu từ xoá nợ không có hồ sơ (3 tỷ) và hoàn nhập dự phòng phải thu khó đòi (9,26 tỷ) — không bền vững và thiếu minh bạch. Kiểm toán viên từ chối đưa ra ý kiến do không chứng kiến kiểm kê tiền mặt/TSCĐ, không nhận được xác nhận công nợ phải thu và thiếu hồ sơ xoá nợ. Giao dịch với bên liên quan (cho vay Chủ tịch HĐQT và công ty liên quan) chiếm tỷ trọng lớn trong tài sản ngắn hạn (~7,4/7,9 tỷ phải thu khác), thiếu lãi suất và tài sản đảm bảo. Rủi ro quản trị ở mức cao, triển vọng đầu tư rất tiêu cực.'),
('VNH_2023_consolidated', 'VNH', 2023, 'consolidated', NULL, NULL, NULL, 1, NULL),
('VNH_2021_consolidated', 'VNH', 2021, 'consolidated', 'Công ty có giao dịch lớn với Công ty CP Ntaco (phải thu ngắn hạn 8,558 tỷ VNĐ, phải trả 1,246 tỷ VNĐ) trong bối cảnh Chủ tịch HĐQT của công ty là đồng Chủ tịch HĐQT của Ntaco. Không có thông tin về lãi suất hay tài sản đảm bảo, tiềm ẩn rủi ro giao dịch không minh bạch và lợi ích nhóm.', 'Áp lực nợ ngắn hạn rất cao (nợ ngắn hạn vượt tài sản ngắn hạn 4,834 tỷ VNĐ). Công ty vay cá nhân lãi suất cao (24%/năm) với tài sản đảm bảo là tín chấp, cho thấy khó khăn trong tiếp cận vốn vay ngân hàng truyền thống.', 'Báo cáo không trình bày chi tiết hàng tồn kho hay dự án xây dựng, phản ánh hoạt động sản xuất kinh doanh cốt lõi gần như đình trệ, chỉ còn doanh thu thương mại nhỏ lẻ.', 8, 'Công ty trong tình trạng tài chính nghiêm trọng với lỗ lũy kế lớn, nợ ngắn hạn vượt tài sản ngắn hạn và bị cưỡng chế hóa đơn. Hoạt động kinh doanh cầm chừng, phụ thuộc vào giao dịch với bên liên quan. Ban lãnh đạo biến động mạnh. Rủi ro hoạt động liên tục là rất cao, triển vọng đầu tư cực kỳ tiêu cực.'),
('VNH_2022_consolidated', 'VNH', 2022, 'consolidated', 'Công ty có giao dịch với bên liên quan bao gồm cho vay không lãi suất từ Chủ tịch HĐQT và các khoản phải thu, phải trả lớn với Công ty Cổ phần Ntaco, nhưng không có bằng chứng rõ ràng về giao dịch bất thường.', 'Áp lực nợ vay thấp do chỉ có khoản vay ngắn hạn nhỏ, nhưng khả năng thanh toán bị đe dọa bởi lỗ lũy kế lớn, nợ thuế và kinh doanh cầm chừng.', 'Không có hàng tồn kho hoặc dự án xây dựng dở dang, do đó rủi ro tồn kho không đáng kể.', 9, 'Tình hình tài chính của công ty rất nghiêm trọng với lỗ lũy kế 76.6 tỷ VNĐ, nợ thuế và hóa đơn bị cương chế. Hoạt động kinh doanh thu hẹp, chỉ còn doanh thu thương mại cầm chừng. Khả năng hoạt động liên tục bị nghi ngờ, triển vọng đầu tư rất tiêu cực.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNH_2020_consolidated', 'VNH', 2020, 'consolidated', 'Công ty có mối quan hệ kinh doanh mật thiết với Công ty CP Ntaco - nơi ông Nguyễn Thanh Sơn (Chủ tịch HĐQT) giữ vai trò đồng chủ tịch HĐQT. Các giao dịch bao gồm: thuê nhà xưởng (990 triệu VND), mượn tiền lớn (8,558 tỷ VND), phát sinh số dư nợ phải trả 1,246 tỷ VND và phải thu 8,558 tỷ VND. Đặc biệt, ông Nguyễn Thanh Sơn có phát sinh giao dịch mượn tiền trong năm trước (tổng gần 11 tỷ VND qua lại). Các giao dịch này tiềm ẩn rủi ro về xung đột lợi ích và minh bạch tài chính.', 'Nợ vay ngắn hạn thấp (250 triệu VND) với lãi suất cao 2%/tháng (24%/năm) từ cá nhân ông Trần Văn Bình, hình thức tín chấp. Tuy nhiên, công ty có lỗ lũy kế rất lớn (-77,4 tỷ VND) và dòng tiền hoạt động kinh doanh âm (-2,084 tỷ VND), cho thấy áp lực thanh khoản đáng kể. Nợ phải trả ngắn hạn tổng cộng 5,8 tỷ VND trong khi tiền mặt chỉ còn 1,02 tỷ VND.', 'Không có thông tin chi tiết về hàng tồn kho hoặc dự án bất động sản dở dang trong thuyết minh báo cáo tài chính. Công ty chủ yếu hoạt động cho thuê nhà xưởng nên rủi ro tồn kho thấp.', 7, 'Công ty Đầu tư Việt Việt Nhật (VNH) có sức khỏe tài chính yếu kém: lỗ lũy kế lên tới 77,4 tỷ VND, doanh thu thuần giảm mạnh 90% từ 20,5 tỷ xuống 2,1 tỷ VND so với năm trước. Dòng tiền hoạt động kinh doanh âm 2,084 tỷ VND. Công ty có giao dịch phức tạp với bên liên quan (Công ty CP Ntaco - liên quan đến Chủ tịch HĐQT) với quy mô lớn. Điểm sáng duy nhất là biên lợi nhuận gộp cao (52%) và kiểm toán viên đưa ra ý kiến chấp nhận toàn phần. Tuy nhiên, tình hình tài chính tổng thể đặt ra nhiều rủi ro cho nhà đầu tư.'),
('VNH_2019_consolidated', 'VNH', 2019, 'consolidated', 'Công ty có giao dịch phức tạp với Chủ tịch Hội đồng Quản trị (Ông Nguyễn Thanh Sơn) và công ty liên quan (Công ty CP Ntaco). Các giao dịch bao gồm cho vay/mượn tiền không rõ lãi suất, thuê nhà xưởng và bù trừ công nợ. Rủi ro về tính minh bạch và khả năng lợi dụng vị trí để thực hiện giao dịch không công bằng.', 'Áp lực nợ vay thấp, chỉ có khoản vay 300 triệu VND từ cá nhân với lãi suất cao (2%/tháng). Không có tài sản thế chấp cụ thể (tín chấp). Khả năng thanh toán nợ vay tốt.', 'Không có thông tin chi tiết về hàng tồn kho hoặc dự án xây dựng dở dang trong báo cáo, khó đánh giá rủi ro tồn kho.', 6, 'Công ty có kết quả kinh doanh tốt năm 2019 với lợi nhuận sau thuế 9,36 tỷ VND, cải thiện đáng kể so với lỗ năm trước. Tuy nhiên, cấu trúc quản trị có rủi ro do giao dịch phức tạp với Chủ tịch HĐQT và công ty liên quan. Nợ vay thấp nhưng lãi suất cao. Cần theo dõi tính minh bạch của các giao dịch bên liên quan và khả năng quản trị doanh nghiệp.'),
('VNH_2018_consolidated', 'VNH', 2018, 'consolidated', 'Công ty có giao dịch mượn tiền lớn với Chủ tịch HĐQT không rõ lãi suất và mục đích sử dụng, đồng thời cho thuê xưởng cho công ty liên quan (Công ty Cổ phần Ntaco) với giá trị cao. Các giao dịch này tiềm ẩn rủi ro về tính công bằng và minh bạch, đặc biệt khi công ty đang trong tình trạng tài chính khó khăn.', 'Nợ ngắn hạn chỉ có khoản vay 300 triệu từ cá nhân với lãi suất rất cao (2%/tháng, tương đương 24%/năm) và không có tài sản đảm bảo. Công ty đang lỗ lũy kế lớn (87,3 tỷ VND), nợ phải trả ngắn hạn vượt tài sản ngắn hạn 8,3 tỷ VND, tạo áp lực thanh toán nghiêm trọng.', 'Công ty không có hàng tồn kho cuối kỳ (giá vốn hàng bán chủ yếu từ dịch vụ gia công) và không có dự án bất động sản dở dang, nên rủi ro tồn kho và dự án chậm tiến độ là không đáng kể.', 7, 'Công ty đang đối mặt với khó khăn tài chính nghiêm trọng: lỗ lũy kế lớn, nợ ngắn hạn vượt tài sản ngắn hạn, khả năng hoạt động liên tục bị nghi ngờ. Doanh thu gia công tăng mạnh trong năm 2018 nhưng biên lợi nhuận gộp cực thấp (0.3%), trong khi chi phí quản lý vẫn đáng kể. Các giao dịch với bên liên quan (cho vay, thuê) và nợ vay lãi suất cao cần được giám sát chặt chẽ. Triển vọng đầu tư tiêu cực nếu không có biện pháp tái cấu trúc hiệu quả.'),
('VNH_2015_consolidated', 'VNH', 2015, 'consolidated', 'Doanh nghiệp có giao dịch lớn với bên liên quan (Công ty TNHH MTV Đồ Hộp Phú Nhật), bao gồm cả doanh thu bán hàng và khoản cho vay. Giá trị phải thu từ bên liên quan chiếm tỷ trọng lớn trong tổng tài sản, cho thấy sự phụ thuộc và rủi ro tập trung cao.', 'Áp lực nợ vay rất cao. Công ty có nợ vay quá hạn (gốc 1.835.130.000 VND, lãi 2.972.286.211 VND) và tình hình kinh doanh gặp khó khăn, không đủ tiền để thanh toán nợ đúng hạn. Tài sản thế chấp chủ yếu là quyền sử dụng đất.', 'Hàng tồn kho (chủ yếu là chi phí SXKD dở dang) có giá trị lớn và phải trích lập dự phòng giảm giá tăng mạnh (1,71 tỷ VND trong năm) do hàng tồn kho chậm luân chuyển.', 8, 'Sức khỏe tài chính của doanh nghiệp rất yếu. Công ty liên tục kinh doanh thua lỗ nặng (LNST lũy kế cuối kỳ âm 49,94 tỷ VND), dòng tiền kinh doanh hoạt động kém, nợ vay quá hạn. Doanh thu và lợi nhuận giảm mạnh so với năm trước. Triển vọng đầu tư rất rủi ro.'),
('VNH_2017_consolidated', 'VNH', 2017, 'consolidated', 'Công ty có giao dịch thuê xưởng với bên liên quan là Công ty Cổ phần Ntaco. Giá trị giao dịch là 1.050.000.000 đồng và có khoản phải thu tiền giữ hộ 482.230.000 đồng. Không phát hiện giao dịch bất thường rõ ràng như cho vay không lãi suất hay mua bán chênh lệch lớn. Rủi ro liên quan ở mức trung bình.', 'Công ty không có nợ vay ngân hàng, nhưng nợ phải trả ngắn hạn (4.740.326.116 đồng) vượt quá tài sản ngắn hạn (507.044.797 đồng), kết quả kinh doanh thua lỗ liên tục dẫn đến lỗ lũy kế lớn (86.072.846.167 đồng), khả năng thanh toán thấp và rủi ro mất khả năng hoạt động liên tục.', 'Hàng tồn kho đã được thanh lý hết do hư hỏng, không còn tồn kho, do đó rủi ro tồn kho không đáng kể.', 7, 'Công ty đang trong tình trạng tài chính yếu kém nghiêm trọng với lỗ lũy kế lớn, nợ phải trả ngắn hạn vượt tài sản ngắn hạn. Hoạt động kinh doanh chính đã thay đổi từ chế biến thủy hải sản sang cho thuê kho, xưởng nhưng doanh thu sụt giảm mạnh. Công ty đã bị cơ quan thuế phong tỏa hóa đơn và bị hủy niêm yết. Khả năng hoạt động liên tục bị nghi ngờ. Triển vọng đầu tư rất tiêu cực.'),
('VNH_2016_consolidated', 'VNH', 2016, 'consolidated', 'Công ty có giao dịch với bên liên quan Công ty CP Đồ hợp Tấn Phát cho thuê kho và gia công, nhưng không có thông tin về giá bất thường hay lạm dụng.', 'Công ty đã thanh toán toàn bộ nợ vay ngân hàng bằng việc bán tài sản, cho thấy áp lực nợ vay đã được giải quyết nhưng phản ánh tình trạng tài chính yếu kém.', 'Hàng tồn kho là sản phẩm thủy sản chế biến tồn kho lâu ngày, đã trích dự phòng giảm giá 50%, cho thấy rủi ro hàng tồn kho cao và khả năng thanh lý thấp.', 7, 'Tổng quan, công ty đang trong tình trạng tài chính khó khăn với lỗ lũy kế lớn, đã bán hầu hết tài sản để trả nợ, và có nghi ngờ về hoạt động liên tục. Triển vọng đầu tư không khả quan.'),
('VNG_2025_consolidated', 'VNG', 2025, 'consolidated', 'Doanh nghiệp có mạng lưới giao dịch bên liên quan phức tạp và rộng lớn với nhiều công ty trong cùng Tập đoàn, công ty liên kết và cá nhân. Các giao dịch bao gồm cho vay, mua bán dịch vụ, hợp tác kinh doanh với giá trị lớn, thường không có tài sản đảm bảo (tín chấp). Điều này tạo rủi ro về tính minh bạch và công bằng trong giá giao dịch, cũng như khả năng thu hồi nợ từ các bên liên quan.', 'Tổng nợ vay và nợ thuê tài chính lên đến hơn 2.736 tỷ VNĐ, trong đó nợ dài hạn chiếm tỷ trọng lớn (1.842 tỷ VNĐ). Công ty phụ thuộc nhiều vào vốn vay ngân hàng và trái phiếu doanh nghiệp với lãi suất cao (trung bình 8-11%/năm). Chi phí lãi vay năm 2025 là 236,7 tỷ VNĐ, chiếm tỷ trọng đáng kể trong lợi nhuận hoạt động kinh doanh. Tài sản đảm bảo chủ yếu là quyền sử dụng đất và bất động sản của các công ty con, tạo rủi ro tập trung.', 'Giá trị hàng tồn kho tương đối thấp (9,1 tỷ VNĐ) so với quy mô doanh nghiệp. Tuy nhiên, chi phí xây dựng cơ bản dở dang lên đến 485,9 tỷ VNĐ, chủ yếu từ Dự án Đồi Thống Nhất và Dự án Đốc Lét. Dự án Đồi Thống Nhất đang trong quá trình điều chỉnh tăng vốn đầu tư từ 497 tỷ lên 1.715 tỷ VNĐ, tạo áp lực tài chính và rủi ro triển khai dự án du lịch lớn trong bối cảnh ngành du lịch biến động.', 7, 'Công ty Du lịch Thành Thành Công có quy mô tổng tài sản lớn (4.435 tỷ VNĐ) và mạng lưới công ty con, liên kết rộng khắp trong ngành du lịch, khách sạn. Tuy nhiên, doanh nghiệp đối mặt với nhiều thách thức: (1) Cấu trúc tài chính đòn bẩy cao với nợ vay lớn, (2) Mạng lưới giao dịch bên liên quan phức tạp tạo rủi ro quản trị, (3) Dự án đầu tư lớn chưa rõ tiến độ giải ngân và hiệu quả, (4) Vấn đề pháp lý liên quan tiền thuê đất mặt nước chuyên dùng có thể phát sinh nghĩa vụ tài chính đáng kể (100,71 tỷ VNĐ). Điểm tích cực là doanh thu năm 2025 tăng trưởng 7% so với năm trước và công ty có dòng tiền từ hoạt động kinh doanh cải thiện so với năm 2024.'),
('VNG_2025_parent', 'VNG', 2025, 'parent', 'Doanh nghiệp có mối quan hệ giao dịch phức tạp với hàng chục công ty trong cùng Tập đoàn và các công ty liên doanh/liên kết, bao gồm mua bán hàng hóa, dịch vụ, cho vay và nhận vay. Các giao dịch này có thể không hoàn toàn được thực hiện trên cơ sở thị trường công bằng, tạo ra rủi ro về lợi ích nhóm và xung đột lợi ích. Đặc biệt, một số khoản vay lớn cho các bên liên quan chỉ dựa trên tín chấp.', 'Công ty có cơ cấu nợ vay đáng kể với tổng nợ vay và nợ thuê tài chính trên 1.000 tỷ VNĐ. Một phần lớn nợ vay (ngắn hạn) được tài trợ từ các bên liên quan. Công ty phải trả chi phí lãi vay hàng năm lớn (khoảng 97 tỷ VNĐ năm 2025), gây áp lực lên dòng tiền hoạt động. Việc phát hành trái phiếu doanh nghiệp cũng là một kênh huy động vốn có chi phí cao và có tài sản đảm bảo.', 'Rủi ro tồn kho của công ty là không đáng kể. Giá trị hàng tồn kho chỉ ở mức hơn 1,2 tỷ VNĐ, chủ yếu là nguyên liệu, vật liệu và hàng hóa phục vụ kinh doanh dịch vụ. Không có dự phòng giảm giá hàng tồn kho. Dự án xây dựng dở dang (Khu phức hợp TTC Gia Lai) có giá trị nhỏ và đang trong quá trình đầu tư.', 7, 'Công ty Cổ phần Du lịch Thành Thành Công đang trong giai đoạn tái cơ cấu và đầu tư mạnh, thể hiện qua doanh thu giảm nhẹ nhưng lợi nhuận sau thuế tăng vọt nhờ hoạt động tài chính (chuyển nhượng đầu tư, lãi cho vay). Tuy nhiên, công ty đối mặt với rủi ro thanh khoản do dòng tiền hoạt động kinh doanh âm nặng nề (-287 tỷ VNĐ) và phụ thuộc lớn vào dòng tiền từ hoạt động tài chính và đầu tư. Mối quan hệ giao dịch phức tạp với bên liên quan và nợ vay cao là những rủi ro quản trị và tài chính chính. Công ty cần cải thiện hiệu quả kinh doanh cốt lõi và quản lý cơ cấu nợ.'),
('VNG_2024_consolidated', 'VNG', 2024, 'consolidated', 'Doanh nghiệp có mạng lưới giao dịch bên liên quan phức tạp và rộng lớn, bao gồm công ty con, công ty liên kết, các công ty trong cùng Tập đoàn và cá nhân thành viên quản lý. Các giao dịch chủ yếu là cung cấp dịch vụ, mua hàng hóa, cho vay và hợp tác kinh doanh. Tuy nhiên, một số khoản cho vay tín chấp (không có tài sản đảm bảo) với lãi suất cao cho các bên liên quan (ví dụ: cho Công ty Đồng Thuay với lãi suất lên đến 15.06%/năm) và lượng lớn phải thu từ chuyển nhượng cổ phần cho bên liên quan (hơn 190 tỷ) đặt ra câu hỏi về tính minh bạch và khả năng thu hồi. Cần giám sát chặt chẽ các giao dịch này để tránh xung đột lợi ích và rủi ro tài chính.', 'Áp lực nợ vay rất lớn. Tổng nợ vay và nợ thuê tài chính cuối năm lên đến gần 2,930 tỷ VND, tăng mạnh so với đầu năm (2,227 tỷ). Nợ ngắn hạn tăng đột biến từ 373 tỷ lên 1,139 tỷ. Công ty dựa nhiều vào vay ngân hàng và phát hành trái phiếu, với tổng lãi suất vay phải trả trong năm là 251 tỷ. Tài sản thế chấp lớn, bao gồm toàn bộ quyền sử dụng đất, nhà cửa và vật kiến trúc của các công ty con và liên kết. Rủi ro thanh toán ngắn hạn là đáng lo ngại khi dòng tiền hoạt động kinh doanh âm 194 tỷ. Khả năng xoay vòng vốn phụ thuộc vào việc tiếp tục vay mới và thoái vốn đầu tư.', 'Rủi ro tồn kho ở mức trung bình. Giá trị hàng tồn kho cuối năm giảm nhẹ còn 7.5 tỷ VND. Tuy nhiên, Công ty có lượng lớn chi phí xây dựng cơ bản dở dang (hơn 412 tỷ), chủ yếu từ Dự án sáp nhập Khu du lịch Thung lũng tinh yêu – Đổi Mộng Mơ – Đổi Thống Nhất. Dự án này tăng 82 tỷ so với đầu năm, cho thấy hoạt động đầu tư mở rộng mạnh, nhưng cũng tiềm ẩn rủi ro nếu dự án bị đình trệ hoặc giá trị không như kỳ vọng.', 7, 'Sức khỏe tài chính của Công ty đối mặt nhiều thách thức. Mặc dù doanh thu giảm nhẹ nhưng lợi nhuận sau thuế của Công ty mẹ chỉ đạt 2.4 tỷ VND, giảm so với năm trước. Đáng chú ý, Công ty đã thực hiện nhiều giao dịch thoái vốn và chuyển nhượng lớn trong năm (TPP Bình Thuận, Palace Bình Thuận, Núi Tà Cú) để cải thiện dòng tiền và cơ cấu tài chính, tạo ra lãi thoái vốn lớn (hơn 191 tỷ từ Palace Bình Thuận). Tuy nhiên, Công ty đang trong giai đoạn đầu tư mở rộng mạnh (dự án Thung lũng tình yêu, Dự án Đốc Lết) bằng đòn bẩy nợ cao. Điểm rủi ro quản trị ở mức cao (7/10) do cấu trúc tập đoàn phức tạp với nhiều giao dịch nội bộ. Triển vọng đầu tư phụ thuộc vào khả năng quản lý rủi ro nợ, hiệu quả của các dự án bất động sản nghỉ dưỡng lớn, và giải quyết các tranh chấp pháp lý (như vụ tiền thuê đất mặt nước chuyên dùng hơn 88 tỷ chưa ghi nhận).'),
('VNG_2024_parent', 'VNG', 2024, 'parent', 'Doanh nghiệp có mạng lưới giao dịch bên liên quan rất phức tạp và quy mô lớn, bao gồm nhiều công ty con, công ty liên kết, cổ đông lớn và thành viên gia đình ban lãnh đạo trong cùng Tập đoàn TTC. Các giao dịch bao gồm cho vay tín chấp không tài sản đảm bảo (ví dụ: cho vay Công ty Cổ phần Du lịch Đồng Thuận 58,5 tỷ VND lãi suất 9,5–12%/năm, cho vay Công ty TNHH Du lịch TTC 47,4 tỷ VND lãi suất 15,06%/năm), trả trước cho người bán lên đến 211 tỷ VND (trong đó 69 tỷ VND cho Công ty con Lâm Đồng), vay từ bên liên quan 95 tỷ VND. Bà Nguyễn Thị Tích Hương (thành viên gia đình ban lãnh đạo) vay từ Công ty tổng cộng 35,3 tỷ VND tín chấp. Giá trị hợp lý các khoản đầu tư chưa được đánh giá chính thức. Rủi ro tiềm ẩn về xung đột lợi ích và giao dịch không theo giá thị trường.', 'Tổng nợ vay lên đến 1.367 tỷ VND, trong đó nợ ngắn hạn 831 tỷ VND và nợ dài hạn 536 tỷ VND. Đáng lo ngại nhất là trái phiếu doanh nghiệp với tổng mệnh giá 1.000 tỷ VND (Bond 1 đáo hạn 04/01/2025 lãi suất 12,28%/năm, Bond 2 đáo hạn 25/11/2027 lãi suất 10,983%/năm), tài sản đảm bảo bao gồm bất động sản và vốn góp tại công ty con. Chi phí lãi vay năm nay lên đến 102,5 tỷ VND, chiếm tỷ trọng lớn trong kết quả kinh doanh. Công ty cũng vay từ nhân viên 40 tỷ VND lãi suất 12%/năm tín chấp. Chi phí lãi vay vượt ngưỡng khấu trừ thuế lũy kế 81,4 tỷ VND chưa được ghi nhận tài sản thuế hoãn lại. Áp lực trả nợ và tái tài trợ là đáng kể.', 'Giá trị hàng tồn kho rất thấp (1,2 tỷ VND) so với quy mô tài sản, chủ yếu là nguyên vật liệu và hàng hóa lưu động, rủi ro tồn kho thấp. Dự án xây dựng dở dang gồm Dự án Khu vui chơi Phú Quốc (1,47 tỷ VND) và Dự án Khu phức hợp TTC Gia Lai (0,39 tỷ VND) đã tồn tại từ năm trước và chưa có tiến triển mới, có nguy cơ bị ứ đọng vốn. Tuy nhiên quy mô không đáng kể so với tổng tài sản.', 6, 'Công ty Cổ phần Du lịch Thành Thành Công (VNG) là công ty mẹ trong Tập đoàn TTC, hoạt động chính trong lĩnh vực du lịch – lưu trú – nhà hàng. Năm 2024, doanh thu thuần giảm 6,7% so với năm trước (từ 352 tỷ xuống 328 tỷ VND), lợi nhuận sau thuế giảm mạnh 78% (từ 18,4 tỷ xuống 4,1 tỷ VND). Công ty phát hành trái phiếu 1.000 tỷ VND lãi suất cao (11–12,28%/năm) và vay mượn từ nhiều nguồn, đẩy tổng nợ vay lên 1.367 tỷ VND, gấp hơn 1,1 lần vốn chủ sở hữu. Điểm sáng là Công ty thực hiện thoái vốn thành công khỏi một số khoản đầu tư (Đặng Huỳnh, Palace Bình Thuận, Ngọc Lan HealthCare), thu về lợi nhuận giao dịch 47,2 tỷ VND. Tuy nhiên, dòng tiền hoạt động kinh doanh âm 162 tỷ VND cho thấy áp lực tài chính thực sự. Mạng lưới giao dịch bên liên quan phức tạp với nhiều khoản cho vay tín chấp lớn là rủi ro quản trị cần lưu ý.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNG_2022_consolidated', 'VNG', 2022, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với bên liên quan, bao gồm mua bán hàng hóa/dịch vụ và cho vay. Các khoản cho vay chủ yếu là tín chấp với lãi suất thị trường. Có giao dịch mua bán tài sản cố định với bên liên quan. Không có bằng chứng rõ ràng về giao dịch bất thường, nhưng mức độ giao dịch lớn đòi hỏi giám sát chặt chẽ.', 'Nợ vay lớn (1,319 tỷ VND), chủ yếu là nợ dài hạn được đảm bảo bằng quyền sử dụng đất, công trình xây dựng và cổ phiếu. Chi phí lãi vay cao (116 tỷ VND), chiếm tỷ trọng đáng kể trong lợi nhuận. Áp lực trả nợ gốc và lãi là đáng kể, đặc biệt với các khoản vay đáo hạn ngắn hạn.', 'Hàng tồn kho không lớn, chủ yếu là nguyên vật liệu và hàng hóa cho hoạt động kinh doanh. Dự án xây dựng dở dang lớn (610 tỷ VND), tập trung vào các dự án du lịch. Cần theo dõi tiến độ và khả năng hoàn thành đúng kế hoạch để tránh rủi ro ứ đọng vốn.', 5, 'Doanh nghiệp hoạt động trong ngành du lịch và khách sạn, năm 2022 ghi nhận sự phục hồi mạnh mẽ về doanh thu và lợi nhuận sau ảnh hưởng của đại dịch. Cơ cấu tài sản lớn với nhiều tài sản cố định và dự án đầu tư. Tuy nhiên, doanh nghiệp sử dụng đòn bẩy tài chính cao, nợ vay chiếm tỷ trọng lớn trong tổng nguồn vốn, gây áp lực về chi phí lãi vay và rủi ro thanh khoản. Các giao dịch với bên liên quan phức tạp cần được giám sát. Triển vọng phụ thuộc vào sự phục hồi bền vững của ngành du lịch và khả năng quản lý nợ hiệu quả.'),
('VNG_2023_parent', 'VNG', 2023, 'parent', 'Doanh nghiệp có nhiều giao dịch với bên liên quan, đặc biệt là các khoản cho vay không có tài sản đảm bảo với lãi suất cao (từ 10,8% đến 15,6%/năm) cho các công ty con và liên kết, tiềm ẩn rủi ro về thu hồi nợ. Ngoài ra, có giao dịch mua bán dịch vụ lớn giữa các bên liên quan, cần đánh giá tính thị trường.', 'Nợ vay tổng cộng hơn 802 tỷ VND, bao gồm nợ ngắn hạn và dài hạn. Có trái phiếu đáo hạn vào tháng 1/2025 với lãi suất cao (9,5%-15,78%/năm) và nhiều khoản vay ngân hàng thế chấp bằng quyền sử dụng đất và cổ phiếu. Áp lực trả nợ lớn, đặc biệt trong bối cảnh ngành du lịch có thể biến động.', 'Hàng tồn kho giá trị nhỏ (khoảng 1,1 tỷ VND), chủ yếu là nguyên vật liệu và hàng hóa, rủi ro thấp. Các dự án xây dựng dở dang có giá trị không lớn (khoảng 5 tỷ VND), trong đó có dự án phần mềm Oracle và dự án bất động sản, nhưng chưa có dấu hiệu ứ đọng.', 6, 'Công ty hoạt động trong ngành du lịch, năm 2023 có lợi nhuận tăng trưởng so với năm trước, nhưng nợ vay ở mức cao và giao dịch với bên liên quan phức tạp. Cần theo dõi khả năng trả nợ và quản trị rủi ro liên quan đến các khoản cho vay nội bộ.'),
('VNG_2023_consolidated', 'VNG', 2023, 'consolidated', 'Nhóm Công ty có mạng lưới giao dịch với các bên liên quan phức tạp và đa dạng, bao gồm nhiều công ty liên kết, công ty trong cùng Tập đoàn và các cá nhân liên quan. Tổng giá trị cho vay các bên liên quan (ngắn hạn và dài hạn) đạt khoảng 158,020 tỷ VND, trong đó nhiều khoản vay tín chấp không có tài sản đảm bảo với lãi suất cao (10,8-15,06%/năm). Đáng chú ý, Công ty cho Công ty Đồng Thuận vay tổng cộng 97,930 tỷ VND tín chấp, Công ty Toàn Hải Vân vay 70 tỷ VND đặt cọc tín chấp. Các giao dịch mua bán dịch vụ nội bộ giữa các công ty liên kết với tổng doanh thu gần 57 tỷ VND trong năm. Việc mua bán chuyển nhượng cổ phần giữa các công ty liên kết cũng phức tạp với nhiều giao dịch thoái vốn trong năm. Rủi ro tập trung vào việc thiếu tài sản đảm bảo cho các khoản cho vay bên liên quan và giá trị giao dịch lớn có thể ảnh hưởng đến dòng tiền.', 'Tổng nợ vay và trái phiếu đạt 2,226,842 tỷ VND, chiếm khoảng 57% tổng tài sản. Chi phí lãi vay trong năm là 181,599 tỷ VND, tăng 56% so với năm trước (116,241 tỷ VND), chiếm tỷ trọng đáng kể trong cơ cấu chi phí. Nợ ngắn hạn ngân hàng 280,480 tỷ VND với lãi suất dao động 5,8-15,78%/năm. Trái phiếu phát hành 497,137 tỷ VND đáo hạn ngày 4/1/2025 với lãi suất cao 9,5-15,78%/năm. Tài sản đảm bảo chủ yếu là quyền sử dụng đất, nhà cửa vật kiến trúc và cổ phiếu của các công ty liên kết trong Tập đoàn. Áp lực trả nợ lớn khi nợ dài hạn đến hạn trong năm sau đáng kể, đặc biệt trái phiếu đáo hạn đầu năm 2025. Công ty có nhiều khoản nợ tín chấp với nhân viên và các công ty liên kết.', 'Giá trị hàng tồn kho thấp (9,1 tỷ VND) và đã giảm nhẹ so với đầu năm, không đáng lo ngại. Tuy nhiên, chi phí xây dựng cơ bản dở dang còn 359,324 tỷ VND (giảm từ 610,084 tỷ VND đầu năm), trong đó dự án sáp nhập Khu du lịch Thung lũng Tình yêu chiếm 299,054 tỷ VND với nhiều chi phí lớn (đền bù 143 tỷ, thuê đất 59,5 tỷ, tư vấn 24,8 tỷ). Dự án Resort TTC Kê Gà vẫn treo 35,216 tỷ VND không thay đổi so với đầu năm. Dự án Khu du lịch Đốc Lết giảm mạnh từ 318,630 tỷ xuống chỉ còn 79,895 triệu VND cho thấy đã xử lý phần lớn. Rủi ro nằm ở tiến độ triển khai dự án du lịch lớn và thời gian hoàn vốn kéo dài.', 5, 'Công ty Cổ phần Du lịch Thành Thành Công (mã VNG) hoạt động trong ngành du lịch - khách sạn đang có dấu hiệu phục hồi mạnh sau đại dịch. Doanh thu thuần năm 2023 đạt 742,666 tỷ VND (tăng 20% so với năm trước), lợi nhuận gộp đạt 256,386 tỷ VND với biên lợi nhuận gộp 34,5%. Lợi nhuận sau thuế của cổ đông công ty mẹ đạt 3,328 tỷ VND (tăng 27%). Tổng tài sản tăng mạnh từ 2,847 tỷ lên 3,910 tỷ VND nhờ mở rộng đầu tư xây dựng và mua lại tài sản. Tuy nhiên, công ty đối mặt với áp lực nợ vay lớn (tổng nợ 2,227 tỷ VND, tỷ lệ nợ/tổng tài sản ~57%) và chi phí lãi vay cao (181,6 tỷ VND). Lợi nhuận từ thoái vốn đầu tư (47,7 tỷ VND ròng) đóng góp đáng kể vào kết quả tài chính. Công ty có mạng lưới giao dịch bên liên quan phức tạp với nhiều khoản cho vay tín chấp lớn. Điểm mạnh là doanh thu tăng trưởng tốt và biên lợi nhuận gộp ổn định; điểm yếu là đòn bẩy tài chính cao và rủi ro từ các dự án xây dựng dở dang lớn.'),
('VNG_2022_parent', 'VNG', 2022, 'parent', 'Công ty có nhiều giao dịch với bên liên quan, bao gồm công ty con, công ty liên kết và các công ty trong cùng Tập đoàn TTC. Các giao dịch này bao gồm mua bán dịch vụ, cho vay với lãi suất cao (10-14%/năm), và trả trước tiền mua dịch vụ. Đặc biệt, Công ty cho vay dài hạn lớn (348 tỷ) cho các công ty liên kết mà không có tài sản đảm bảo, tiềm ẩn rủi ro tập trung và khả năng thu hồi nợ. Cần kiểm soát chặt chẽ để tránh xung đột lợi ích và ảnh hưởng đến hiệu quả hoạt động.', 'Tổng nợ phải trả là 913 tỷ VNĐ, chiếm 43% tổng tài sản. Trong đó, nợ ngắn hạn 301 tỷ, nợ dài hạn 612 tỷ. Công ty có nhiều khoản vay ngân hàng với tài sản đảm bảo là quyền sử dụng đất, quyền khai thác du lịch và cổ phiếu. Chi phí lãi vay cao (76.7 tỷ) ảnh hưởng lớn đến lợi nhuận. Công ty cũng phát hành trái phiếu 500 tỷ, tạo áp lực trả nợ lớn trong dài hạn. Cần theo dõi sát diễn biến dòng tiền để đảm bảo thanh toán đúng hạn.', 'Hàng tồn kho chỉ có 977 triệu VNĐ, chủ yếu là nguyên vật liệu và hàng hóa, không đáng kể so với tổng tài sản. Dự án xây dựng dở dang gồm hai dự án với tổng giá trị 1.86 tỷ VNĐ, quy mô nhỏ và không có dấu hiệu ứ đọng. Rủi ro tồn kho thấp.', 7, 'Công ty có sự tăng trưởng mạnh về doanh thu (353.7 tỷ, tăng 182%) và lợi nhuận sau thuế (10.78 tỷ, tăng 162%) so với năm trước, nhờ hoạt động kinh doanh du lịch phục hồi. Tuy nhiên, cơ cấu tài chính có rủi ro với nợ vay lớn, đặc biệt là nợ dài hạn và trái phiếu. Chi phí lãi vay cao ăn mòn lợi nhuận. Công ty có nhiều giao dịch với bên liên quan, cần giám sát chặt chẽ. Dự án đầu tư dài hạn lớn vào các công ty con và liên kết nhưng chưa mang lại lợi nhuận đột biến. Triển vọng phụ thuộc vào ngành du lịch và khả năng quản lý nợ.'),
('VNG_2021_consolidated', 'VNG', 2021, 'consolidated', 'Công ty có mối quan hệ giao dịch phức tạp với nhiều bên liên quan thuộc cùng Tập đoàn TTC, bao gồm Công ty Cổ phần Đầu tư Thành Thành Công (cổ đông lớn), Công ty Cổ phần Địa ốc Sài Gòn Thương Tín, Công ty Cổ phần Du lịch Núi Tà Cú và nhiều công ty con, công ty liên kết khác. Các giao dịch bao gồm mua bán dịch vụ, cho vay, bán tài sản cố định với giá trị hàng chục tỷ đồng. Đặc biệt, Công ty có nhiều khoản cho vay với lãi suất thấp (1.5%/năm cho bà Lovia Huang) cho các bên liên quan, đồng thời ghi nhận lãi cho vay lớn từ các công ty trong Tập đoàn. Tổng phải thu và cho vay ngắn hạn/dài hạn từ các bên liên quan lên tới hàng trăm tỷ đồng. Công ty cũng ghi nhận doanh thu từ chuyển nhượng vốn góp trong công ty con cho các nhà đầu tư không rõ danh tính trong Tập đoàn. Rủi ro là các giao dịch có thể không được thực hiện trên cơ sở thị trường, tiềm ẩn nguy cơ chuyển giá hoặc chuyển tài sản giữa các thực thể trong Tập đoàn.', 'Tổng nợ vay và nợ thuê tài chính cuối năm 2021 là 987.779.870.989 VND (xấp xỉ 988 tỷ VND), bao gồm vay ngắn hạn 433.821.031.159 VND và vay dài hạn 553.958.839.830 VND. Tỷ lệ nợ vay/vốn chủ sở hữu rất cao (gần 90%). Phần lớn nợ vay được thế chấp bằng quyền sử dụng đất, nhà cửa, vật kiến trúc và các tài sản cố định của nhóm công ty, dự án Dốc Lết, dự án Kê Gà. Chi phí lãi vay trong năm là 65.857.474.794 VND. Công ty cũng vay từ các bên liên quan tổng cộng hơn 119 tỷ VND (ngắn hạn 58,1 tỷ + dài hạn 61,4 tỷ). Nợ vay từ ngân hàng chiếm phần lớn với lãi suất từ 6.0% đến 10.5%/năm. Áp lực trả nợ trong ngắn hạn lớn do nhiều khoản vay đáo hạn trong năm 2022.', 'Hàng tồn kho tổng cộng 6.784.147.053 VND, không có dự phòng giảm giá cuối năm 2021 (đã hoàn nhập 245.086.378 VND). Phần lớn hàng tồn kho là nguyên vật liệu (3.862.064.484 VND) và hàng hóa (1.438.695.785 VND). Rủi ro tồn kho ở mức trung bình do giá trị tương đối nhỏ so với tổng tài sản. Tuy nhiên, chi phí xây dựng cơ bản dở dang rất lớn (290.721.548.882 VND), chiếm phần đáng kể tài sản dài hạn, đặc biệt là dự án Khu du lịch Đốc Lét (204 tỷ VND) và dự án Resort TTC Kê Gà (35 tỷ VND). Các dự án này có tiến độ chậm và tiềm ẩn rủi ro chi phí vượt dự toán.', 7, 'Công ty Cổ phần Du lịch Thành Thành Công (TTCT Group) hoạt động trong ngành du lịch - khách sạn chịu ảnh hưởng nặng nề bởi COVID-19 năm 2021, với doanh thu thuần sụt giảm 60% (từ 460 tỷ xuống 182 tỷ VND) và lỗ gộp 26 tỷ VND từ hoạt động kinh doanh cốt lõi. Tuy nhiên, lợi nhuận trước thuế vẫn đạt 6,59 tỷ VND nhờ lợi nhuận lớn từ chuyển nhượng vốn góp trong các công ty con (180 tỷ VND doanh thu hoạt động tài chính). Công ty có cấu trúc tài chính rủi ro với nợ vay gần 988 tỷ VND, tỷ lệ đòn bẩy cao, và dòng tiền hoạt động kinh doanh âm 175 tỷ VND. Mạng lưới giao dịch bên liên quan phức tạp trong Tập đoàn TTC là điểm đáng lưu ý. Công ty đang triển khai nhiều dự án xây dựng lớn với tổng chi phí gần 290 tỷ VND, đòi hỏi nguồn vốn đầu tư đáng kể. Triển vọng ngắn hạn phụ thuộc vào khả năng phục hồi ngành du lịch sau đại dịch và quản lý hiệu quả các dự án xây dựng đang dang dở.'),
('VNG_2021_parent', 'VNG', 2021, 'parent', 'Doanh nghiệp có nhiều giao dịch phức tạp với các bên liên quan, bao gồm cho vay, mua bán dịch vụ, thanh lý tài sản và thanh toán lãi vay. Các giao dịch này có thể tạo rủi ro về xung đột lợi nhuận, giao dịch không minh bạch và ảnh hưởng đến lợi ích của cổ đông thiểu số.', 'Nợ vay ngắn hạn và dài hạn chiếm tỷ trọng lớn trong cơ cấu vốn, với tổng nợ phải trả là 515.202.901.931 VND. Tài sản thế chấp bao gồm cổ phiếu và quyền khai thác bất động sản. Áp lực lãi vay cao, chi phí lãi vay năm 2021 là 29.845.816.613 VND, tăng so với năm trước. Doanh nghiệp cần quản lý dòng tiền để đáp ứng các nghĩa vụ nợ.', 'Hàng tồn kho ở mức thấp (790.655.590 VND), chủ yếu là nguyên vật liệu và hàng hóa, không có dự án xây dựng dở dang lớn. Rủi ro tồn kho thấp, nhưng doanh nghiệp chịu ảnh hưởng từ đại dịch Covid-19 dẫn đến tồn kho giảm.', 6, 'Công ty Du lịch Thành Thành Công chịu tác động nặng nề từ đại dịch Covid-19, với doanh thu thuần giảm mạnh từ 231.724.234.688 VND năm 2020 xuống 125.199.541.569 VND năm 2021. Lợi nhuận sau thuế chỉ còn 4.114.179.163 VND. Cơ cấu tài chính có đòn bẩy cao, với nợ phải trả chiếm tỷ trọng lớn và nhiều giao dịch bên liên quan. Công ty có lỗ tính thuế chuyển sang các năm sau. Triển vọng phụ thuộc vào sự phục hồi của ngành du lịch và khả năng quản lý rủi ro tài chính.'),
('VNG_2020_parent', 'VNG', 2020, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm cho vay, mua bán dịch vụ, và cổ tức. Tổng giá trị phải thu ngắn hạn từ bên liên quan là 31.148.242.144 VND và phải trả ngắn hạn khác cho bên liên quan là 48.617.121.383 VND. Các giao dịch này có thể tiềm ẩn rủi ro về tính công bằng và minh bạch, đặc biệt là các khoản cho vay không lãi suất hoặc lãi suất ưu đãi.', 'Tổng nợ vay ngắn hạn và dài hạn là 241.531.695.997 VND, với lãi suất dao động từ 4,6% đến 12%/năm. Công ty sử dụng nhiều tài sản thế chấp như cổ phiếu SBT, quyền khai thác du lịch, và phương tiện vận tải. Nợ vay tăng so với năm trước, tạo áp lực trả nợ và chi phí lãi vay.', 'Hàng tồn kho giảm từ 1.373.906.553 VND xuống 1.042.124.108 VND, không có dự phòng giảm giá hàng tồn kho. Dự án xây dựng dở dang tăng nhẹ lên 1.836.037.336 VND, chủ yếu là Dự án Khu vui chơi Phú Quốc. Không có dấu hiệu ứ đọng lớn.', 7, 'Công ty hoạt động trong lĩnh vực du lịch và lưu trú, chịu ảnh hưởng nặng nề từ đại dịch COVID-19 với doanh thu thuần giảm 33,6% so với năm trước. Lợi nhuận sau thuế đạt 30.744.907.537 VND, giảm 11,3%. Dòng tiền từ hoạt động kinh doanh âm 61.590.052.937 VND. Công ty có mạng lưới công ty con và liên kết rộng, nhưng giao dịch nội bộ phức tạp. Nợ vay tăng cao, chủ yếu phục vụ hoạt động kinh doanh và đầu tư. Tổng tài sản tăng 9,9% nhờ đầu tư dài hạn. Triển vọng phụ thuộc vào sự phục hồi của ngành du lịch.'),
('VNG_2019_consolidated', 'VNG', 2019, 'consolidated', 'Công ty có giao dịch bên liên quan rất lớn, đặc biệt với Công ty Cổ phần Đầu tư Thành Thành Công (cổ đông lớn) với tổng cho vay ngắn hạn 69,6 tỷ VNĐ và dài hạn 26,5 tỷ VNĐ; mua dịch vụ 16,9 tỷ VNĐ; góp vốn 44,5 tỷ VNĐ. Ngoài ra, công ty cho vay tín chấp lớn đối với cá nhân (bà Lovia Huang 11 tỷ VNĐ) và nhiều giao dịch mua bán dịch vụ/hàng hóa với các công ty trong cùng Tập đoàn TTC. Mặc dù các giao dịch được thuyết minh đầy đủ, quy mô cho vay lớn với bên liên quan tạo rủi ro tập trung và tiềm ẩn xung đột lợi ích.', 'Tổng nợ vay là 808,5 tỷ VNĐ (nợ ngắn hạn 316,8 tỷ + nợ dài hạn 491,7 tỷ VNĐ), chiếm tỷ trọng cao trong tổng tài sản. Nợ dài hạn chủ yếu từ VietinBank (245,7 tỷ) và OCB (39,9 tỷ) với lãi suất 7-10,5%/năm. Hầu hết nợ được thế chấp bằng quyền sử dụng đất, nhà cửa, vật kiến trúc và cổ phiếu của các công ty con/liên kết. Chi phí lãi vay năm 2019 là 54,4 tỷ VNĐ, áp lực trả nợ lớn. Công ty có dòng tiền từ hoạt động kinh doanh 66 tỷ VNĐ, không đủ bù đắp chi phí đầu tư 292,6 tỷ VNĐ, phải dựa vào huy động vốn vay mới (802,4 tỷ VNĐ vay mới trong năm).', 'Hàng tồn kho cuối năm 12,7 tỷ VNĐ, tăng nhẹ so với đầu năm (11,5 tỷ), bao gồm nguyên vật liệu, hàng hóa, công cụ dụng cụ và thành phẩm. Phần lớn giá trị nằm ở dự án xây dựng dở dang (268,1 tỷ VNĐ) với nhiều dự án lớn đang triển khai (Đốc Lết 128,2 tỷ, Bến Tre 31,7 tỷ, TTC Kê Gà 30 tỷ, Resort Bầu Trúc 16,8 tỷ...). Rủi ro chủ yếu là tiến độ thi công, biến động thị trường bất động sản và du lịch, đặc biệt trong bối cảnh COVID-19 có thể ảnh hưởng đến nhu cầu du lịch.', 6, 'Công ty Cổ phần Du lịch Thành Thành Công (VNG) hoạt động trong lĩnh vực du lịch, lưu trú và bất động sản. Năm 2019, doanh thu thuần đạt 914,8 tỷ VNĐ (giảm nhẹ so với năm trước 919,3 tỷ), lợi nhuận sau thuế giảm mạnh từ 68,8 tỷ xuống 37,3 tỷ VNĐ, EPS giảm từ 436 xuống 189 VNĐ. Công ty đang trong giai đoạn mở rộng mạnh với nhiều dự án resort lớn (tổng chi phí xây dựng dở dang 268 tỷ VNĐ) và đã thực hiện nhiều thương vụ M&A (mua NLD và TTP với tổng giá phí 136 tỷ VNĐ). Nợ vay cao (808,5 tỷ), lỗ lũy kế 45,2 tỷ VNĐ và dòng tiền hoạt động kinh doanh không đủ bù đắp đầu tư là những rủi ro tài chính đáng lưu ý. Công ty có mối quan hệ kinh doanh phức tạp với nhiều bên liên quan trong hệ sinh thái TTC. Triển vọng ngắn hạn bị ảnh hưởng tiêu cực bởi đại dịch COVID-19 đối với ngành du lịch.'),
('VNG_2020_consolidated', 'VNG', 2020, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với các bên liên quan trong cùng tập đoàn (Công ty Cổ phần Địa ốc Sài Gòn Thương Tín, Công ty Cổ phần Thành Thành Công - Biên Hòa, Công ty Cổ phần Chè Thành Ngọc) và cổ đông lớn (Công ty Cổ phần Đầu tư Thành Thành Công). Các giao dịch bao gồm cho vay, mua bán dịch vụ, hàng hóa với giá trị đáng kể. Cần lưu ý khả năng giao dịch không theo giá thị trường hoặc cho vay không lãi suất/thấp lãi suất.', 'Nợ vay ở mức cao (tổng nợ vay và nợ thuê tài chính cuối năm là 838.443.426.422 VND), chủ yếu là nợ dài hạn ngân hàng. Tài sản đảm bảo chủ yếu là bất động sản (quyền sử dụng đất, nhà cửa) và cổ phiếu. Công ty có dòng tiền hoạt động kinh doanh dương (13.056.512.821 VND) nhưng không đủ bù đắp hoạt động đầu tư, dẫn đến tăng vay nợ. Áp lực trả nợ trung bình, cần theo dõi khả năng tạo dòng tiền từ hoạt động kinh doanh.', 'Hàng tồn kho giảm từ 12.667.821.280 VND xuống 8.298.144.689 VND, có trích lập dự phòng giảm giá 245.086.378 VND. Dự án xây dựng cơ bản dở dang lớn (260.936.305.542 VND), tập trung vào các dự án du lịch, bất động sản. Rủi ro về tiến độ và hiệu quả đầu tư các dự án này.', 6, 'Nhóm Công ty hoạt động trong ngành du lịch - dịch vụ, chịu ảnh hưởng nặng nề của đại dịch COVID-19 trong năm 2020, doanh thu thuần giảm 49.7% so với năm trước. Tuy nhiên, lợi nhuận sau thuế vẫn dương (20.710.020.092 VND) nhờ lãi lớn từ thanh lý các công ty con (92.478.011.842 VND). Nợ vay tăng, Công ty đã tái cơ cấu tài chính và dùng thặng dư vốn cổ phần xóa lỗ lũy kế. Triển vọng phụ thuộc vào sự phục hồi của ngành du lịch và tiến độ các dự án đầu tư. Điểm rủi ro quản trị ở mức trung bình do có nhiều giao dịch với bên liên quan và thay đổi nhân sự cấp cao trong năm.'),
('VNG_2017_parent', 'VNG', 2017, 'parent', 'Giao dịch với các bên liên quan chủ yếu là mua bán dịch vụ và cho vay trong nội bộ nhóm, không có bằng chứng về giao dịch bất thường hoặc giá chuyển nhượng không hợp lý. Tuy nhiên, mức độ tập trung vào các công ty con có thể tạo rủi ro liên đới.', 'Áp lực nợ vay cao với tổng nợ phải trả lớn hơn tài sản ngắn hạn, dẫn đến nghi ngờ về khả năng hoạt động liên tục. Công ty có nhiều khoản vay với lãi suất điều chỉnh và thế chấp bằng tài sản, nhưng khả năng thanh toán phụ thuộc vào dòng tiền từ hoạt động kinh doanh.', 'Hàng tồn kho chủ yếu là nguyên vật liệu và công cụ dụng cụ, giá trị nhỏ và không có dự phòng, rủi ro thấp. Không có dự án xây dựng dở dang hay bất động sản đầu tư lớn.', 6, 'Công ty có doanh thu tăng trưởng mạnh trong năm 2017 nhờ mở rộng hoạt động và sáp nhập, nhưng lợi nhuận sau thuế giảm. Tài sản ngắn hạn nhỏ hơn nợ ngắn hạn, cho thấy áp lực thanh khoản. Công ty đã tăng vốn lớn để đầu tư vào công ty con, tuy nhiên cần theo dõi hiệu quả các khoản đầu tư này. Triển vọng phụ thuộc vào khả năng quản lý nợ và cải thiện dòng tiền.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNG_2017_consolidated', 'VNG', 2017, 'consolidated', 'Doanh nghiệp có giao dịch đáng kể với bên liên quan là cổ đông lớn Công ty Cổ phần Đầu tư Thành Thành Công, bao gồm doanh thu bán hàng, cho vay và mua bán hàng hóa. Các khoản cho vay có lãi suất thị trường, nhưng sự tập trung giao dịch có thể tạo rủi ro nếu có xung đột lợi ích.', 'Nợ vay tăng mạnh từ 136 tỷ lên 438 tỷ, với tỷ lệ nợ trên vốn chủ sở hữu cao. Nhiều khoản vay được đảm bảo bằng tài sản cố định, và một số lãi suất điều chỉnh, tạo áp lực trả nợ nếu lãi suất tăng.', 'Hàng tồn kho tăng từ 1,2 tỷ lên 12,5 tỷ, chủ yếu là hàng hóa và nguyên liệu. Dự án xây dựng dở dang lớn (67 tỷ) cần theo dõi tiến độ và chi phí để tránh ứ đọng.', 7, 'Công ty tăng trưởng mạnh về quy mô nhờ sáp nhập công ty con, nhưng nợ vay tăng cao, cần quản lý rủi ro tài chính. Triển vọng phụ thuộc vào ngành du lịch và khả năng kiểm soát chi phí.'),
('VNG_2019_parent', 'VNG', 2019, 'parent', 'Doanh nghiệp có giao dịch phức tạp và thường xuyên với các bên liên quan, bao gồm công ty con, công ty liên kết và cổ đông lớn. Các giao dịch bao gồm cho vay, mua bán dịch vụ, và chia cổ tức. Mặc dù không có dấu hiệu bất thường rõ ràng, quy mô giao dịch lớn đòi hỏi sự giám sát chặt chẽ để đảm bảo tính minh bạch và công bằng.', 'Áp lực nợ vay tương đối cao với tổng nợ ngắn hạn và dài hạn khoảng 189 tỷ VNĐ. Công ty sử dụng tài sản thế chấp như cổ phiếu và quyền khai thác du lịch. Lãi suất dao động từ 7% đến 12%/năm. Cần theo dõi khả năng thanh toán và quản lý nợ để tránh rủi ro thanh khoản.', 'Hàng tồn kho ở mức thấp (khoảng 1.37 tỷ VNĐ), chủ yếu là nguyên vật liệu và hàng hóa. Dự án xây dựng dở dang (Dự án Khu vui chơi Phú Quốc) có giá trị 1.71 tỷ VNĐ, nhưng không có thông tin về tiến độ hay rủi ro ứ đọng. Nhìn chung, rủi ro tồn kho không đáng kể.', 6, 'Công ty Du lịch Thành Thành Công có kết quả kinh doanh ổn định với doanh thu thuần 348.77 tỷ VNĐ và lợi nhuận sau thuế 34.69 tỷ VNĐ. Tuy nhiên, công ty có mối quan hệ tài chính phức tạp với các bên liên quan, nợ vay tương đối lớn và hoạt động đầu tư dài hạn vào công ty con. Triển vọng đầu tư phụ thuộc vào khả năng quản lý rủi ro liên quan đến giao dịch nội bộ và áp lực nợ.'),
('VNG_2018_parent', 'VNG', 2018, 'parent', 'Giao dịch với bên liên quan bao gồm cho vay không có tài sản bảo đảm, nhưng tổng giá trị không đáng kể so với tài sản công ty.', 'Nợ ngắn hạn vượt tài sản ngắn hạn, gây rủi ro thanh khoản. Công ty có kế hoạch tài trợ từ cổ đông và gia hạn nợ để đảm bảo hoạt động liên tục.', 'Hàng tồn kho không có dự phòng giảm giá, chủ yếu là nguyên liệu và hàng hóa thông thường, rủi ro thấp.', 6, 'Công ty có lợi nhuận tăng trưởng mạnh năm 2018 nhờ doanh thu tư vấn và cổ tức từ công ty con. Tuy nhiên, rủi ro thanh khoản cao do cơ cấu nợ ngắn hạn lớn. Triển vọng phụ thuộc vào khả năng quản lý nợ và hiệu quả kinh doanh của công ty con.'),
('VNG_2018_consolidated', 'VNG', 2018, 'consolidated', 'Công ty có giao dịch đáng kể với Công ty Cổ phần Đầu tư Thành Thành Công (cổ đông lớn). Các giao dịch bao gồm cho vay lớn với lãi suất thấp hơn thị trường (10.5%-11% so với lãi suất điều chỉnh ngân hàng), mua bán hàng hóa dịch vụ. Điều này tiềm ẩn rủi ro giao dịch không theo giá thị trường và có thể ảnh hưởng đến lợi ích của các cổ đông thiểu số.', 'Nợ vay của công ty khá lớn với tổng nợ vay ngắn hạn và dài hạn là 583.664 tỷ VNĐ. Công ty thế chấp nhiều tài sản (bất động sản, cổ phiếu) để đảm bảo nợ. Áp lực nợ vay trung bình, nhưng doanh nghiệp có dòng tiền hoạt động kinh doanh dương (113 tỷ năm 2018) và các khoản vay đáo hạn rải rác.', 'Hàng tồn kho trị giá 11.540 tỷ VNĐ chủ yếu là nguyên liệu và hàng hóa, không có dự phòng giảm giá. Các dự án xây dựng dở dang (109 tỷ) bao gồm nhiều dự án bất động sản du lịch, có rủi ro ứ đọng do thị trường du lịch biến động và dự án kéo dài.', 6, 'Công ty có kết quả kinh doanh năm 2018 cải thiện (lợi nhuận sau thuế tăng từ 35.7 tỷ lên 68.8 tỷ VNĐ). Tuy nhiên, công ty có nhiều giao dịch với bên liên quan, nợ vay lớn và đầu tư vào nhiều dự án bất động sản du lịch. Rủi ro quản trị ở mức trung bình cao do tập trung giao dịch với cổ đông lớn và phức tạp trong cơ cấu tập đoàn.'),
('VNG_2016_consolidated', 'VNG', 2016, 'consolidated', 'Doanh nghiệp có giao dịch đáng kể với Công ty CP Đầu tư Thành Thành Công (cổ đông lớn) bao gồm cho vay, phải thu/phải trả và doanh thu. Giao dịch với bên liên quan tập trung vào một chủ thể, cần đánh giá tính thị trường và xung đột lợi ích tiềm tàng.', 'Doanh nghiệp có áp lực nợ vay lớn với tổng nợ vay hơn 136 tỷ VNĐ, bao gồm cả ngắn hạn và dài hạn. Nợ tập trung tại một số ngân hàng và tổ chức tín dụng. Tài sản thế chấp chủ yếu là bất động sản và tài sản cố định. Khả năng thanh toán phụ thuộc vào dòng tiền kinh doanh và doanh thu từ hoạt động tài chính.', 'Tồn kho giảm mạnh từ 23 tỷ xuống 1.2 tỷ VNĐ, chủ yếu do giảm hàng hóa. Dự án xây dựng dở dang còn lại 967 triệu VNĐ (công trình Trung tâm tiệc cuối Đồng Khởi) có thể bị ảnh hưởng bởi tiến độ và chi phí phát sinh.', 6, 'Doanh nghiệp có sự tăng trưởng mạnh về doanh thu và lợi nhuận trong năm 2016, nhưng nợ vay cao và tập trung vào một số chủ nợ. Giao dịch với bên liên quan (cổ đông lớn) đáng chú ý, đòi hỏi giám sát chặt chẽ để tránh xung đột lợi ích. Công ty đang trong giai đoạn tái cấu trúc với việc thoái vốn khỏi một số công ty con và chuyển đổi dự án. Triển vọng phụ thuộc vào khả năng quản lý nợ và hiệu quả kinh doanh từ hoạt động du lịch - khách sạn.'),
('VNG_2016_parent', 'VNG', 2016, 'parent', 'Công ty có nhiều giao dịch với bên liên quan, bao gồm doanh thu bán hàng và dịch vụ, chi phí sử dụng dịch vụ và lãi vay phát sinh với công ty con và cổ đông lớn. Số dư phải thu và phải trả với các bên liên quan cũng đáng kể, cho thấy sự phụ thuộc và tiềm ẩn rủi ro giao dịch không theo giá thị trường.', 'Nợ vay ở mức trung bình với tổng nợ vay 100.394.649.723 VND, chủ yếu là vay dài hạn từ Ngân hàng Phương Đông với lãi suất 8.5%/năm và thế chấp bằng quyền sử dụng đất. Công ty có đủ dòng tiền từ hoạt động kinh doanh để trả nợ, nhưng cần theo dõi lãi suất thả nổi và áp lực trả nợ gốc ngắn hạn.', 'Hàng tồn kho ở mức thấp, chủ yếu là công cụ, dụng cụ và nguyên liệu cho hoạt động kinh doanh khách sạn, không có dự án dở dang lớn. Rủi ro tồn kho thấp.', 4, 'Công ty đạt kết quả kinh doanh tốt năm 2016 với lợi nhuận sau thuế 7.605.225.190 VND, tăng mạnh so với năm trước. Tuy nhiên, công ty có nhiều giao dịch với bên liên quan, nợ vay ở mức kiểm soát và có kế hoạch tăng vốn mạnh mẽ trong năm 2017 để đầu tư vào các công ty mục tiêu, triển vọng tăng trưởng nhưng cần giám sát rủi ro quản trị.'),
('VNG_2015_consolidated', 'VNG', 2015, 'consolidated', 'Công ty có giao dịch cho vay với các bên liên quan là cổ đông lớn với lãi suất áp dụng theo thỏa thuận (10.5%/năm và 10%/năm) và không có tài sản thế chấp. Rủi ro liên quan đến việc thu hồi nợ từ các bên liên quan có thể cao nếu tình hình tài chính của họ xấu đi.', 'Công ty có nợ vay tăng mạnh với lãi suất từ 7% đến 10.5%/năm, tài sản thế chấp chủ yếu là bất động sản và quyền sử dụng đất. Áp lực trả nợ cao do nợ ngắn hạn chiếm tỷ trọng lớn, nhưng được hỗ trợ bởi cam kết tài trợ từ tập đoàn mẹ.', 'Hàng tồn kho tăng đáng kể do dự án sửa chữa khách sạn Golf Cần Thơ, có rủi ro ứ đọng nếu dự án không hoàn thành đúng tiến độ hoặc không hiệu quả.', 7, 'Công ty tăng trưởng doanh thu mạnh nhưng lợi nhuận gộp giảm do chi phí tăng. Nợ vay tăng đáng kể để tài trợ dự án sửa chữa khách sạn, có cam kết tài trợ từ tập đoàn mẹ giúp giảm rủi ro thanh khoản. Tuy nhiên, rủi ro tài chính và quản trị ở mức trung bình cao do đòn bẩy tài chính lớn và giao dịch với bên liên quan.'),
('VNG_2015_parent', 'VNG', 2015, 'parent', 'Doanh nghiệp có giao dịch với các bên liên quan bao gồm công ty con, công ty liên kết và đối tác hợp tác kinh doanh. Có khoản vay lớn (31,5 tỷ VNĐ) không có tài sản đảm bảo cho Công ty CP Đầu tư Thành Thành Công, và khoản phải thu lớn (5,35 tỷ VNĐ) từ công ty liên kết VinaGolf Angkor, tiềm ẩn rủi ro về khả năng thu hồi và quản lý vốn.', 'Áp lực nợ vay cao với tổng nợ vay hơn 150 tỷ VNĐ, trong đó nợ ngắn hạn chiếm phần lớn. Công ty có dấu hiệu mất cân đối về thanh khoản nhưng được Tập đoàn Thành Thành Công cam kết tài trợ vốn. Các khoản vay chủ yếu dùng cho sửa chữa khách sạn và bổ sung vốn lưu động, có tài sản thế chấp là bất động sản và quyền sử dụng đất.', 'Tồn kho giảm so với đầu năm, chủ yếu là nguyên liệu và hàng hóa. Dự án xây dựng dở dang tăng mạnh, đặc biệt dự án sửa chữa khách sạn Golf Cần Thơ với tổng mức đầu tư 69,2 tỷ VNĐ, dự kiến hoàn thành năm 2016. Rủi ro từ việc triển khai dự án và khả năng hoàn thành đúng tiến độ.', 6, 'Công ty Du lịch Thành Thành Công có doanh thu tăng trưởng mạnh nhờ phát triển dịch vụ lữ hành, nhưng biên lợi nhuận gộp rất thấp (khoảng 0,7%). Nợ vay cao và tập trung vào dự án sửa chữa khách sạn, cần nguồn vốn lớn. Quản trị có rủi ro do giao dịch với bên liên quan và nợ ngắn hạn cao. Triển vọng phụ thuộc vào khả năng hoàn thành dự án và hỗ trợ từ tập đoàn.'),
('VNF_2025_consolidated', 'VNF', 2025, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm cho vay và mua bán dịch vụ, nhưng không phát hiện giao dịch bất thường rõ ràng. Tuy nhiên, quy mô giao dịch đáng kể cần được giám sát.', 'Nợ vay chủ yếu là ngắn hạn với lãi suất hợp lý và có tài sản đảm bảo. Áp lực nợ vay thấp so với tổng tài sản.', 'Hàng tồn kho chiếm tỷ trọng rất nhỏ trong tổng tài sản, không có rủi ro tồn kho dở dang.', 4, 'Tập đoàn có sức khỏe tài chính ổn định với tỷ lệ nợ thấp và lợi nhuận đều đặn. Tuy nhiên, doanh thu giảm so với năm trước và lợi nhuận gộp biên giảm. Triển vọng trung bình.'),
('VNF_2025_parent', 'VNF', 2025, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan, đặc biệt với công ty mẹ Transimex và các công ty con/liên kết, bao gồm cho vay lớn (50 tỷ VNĐ) và nhận cổ tức đáng kể. Điều này tiềm ẩn rủi ro về xung đột lợi ích và tính minh bạch của giao dịch, mặc dù lãi suất cho vay không được công bố rõ ràng.', 'Áp lực nợ vay ngắn hạn thấp với khoản vay 4,4 tỷ VNĐ từ Shinhan Việt Nam, lãi suất 4,5%/năm và thời hạn ngắn. Công ty có tài sản lưu động đủ để đáp ứng nghĩa vụ nợ, nhưng cần giám sát thanh khoản do các khoản phải trả khác cao.', 'Tồn kho trị giá 3 tỷ VNĐ, chiếm tỷ trọng nhỏ trong tổng tài sản. Công ty hoạt động trong lĩnh vực dịch vụ logistics nên tồn kho chủ yếu là hàng hóa tiêu dùng hoặc vật tư, rủi ro tồn đọng thấp.', 5, 'Công ty có vị thế tài chính ổn định với doanh thu tăng trưởng, lợi nhuận sau thuế cao. Tuy nhiên, rủi ro quản trị trung bình do giao dịch phức tạp với các bên liên quan và dự phòng đầu tư lớn vào công ty liên kết. Triển vọng đầu tư tích cực trong ngắn hạn nhờ hoạt động logistics thuận lợi, nhưng cần theo dõi các giao dịch nội bộ.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNF_2024_consolidated', 'VNF', 2024, 'consolidated', 'Công ty có giao dịch với công ty mẹ Transimex bao gồm cho vay tín chấp 50 tỷ VNĐ với lãi suất 5.5%/năm, thanh toán cổ tức và dịch vụ. Giao dịch với các bên liên quan khác chủ yếu là dịch vụ và cổ tức, không có dấu hiệu bất thường lớn nhưng cần theo dõi.', 'Nợ vay chủ yếu là nợ ngắn hạn ngân hàng với lãi suất 5.5%/năm, đảm bảo bằng tiền gửi. Áp lực nợ thấp do thời hạn ngắn và tài sản đảm bảo.', 'Hàng tồn kho giá trị nhỏ 2.4 tỷ VNĐ, không có dự phòng giảm giá, rủi ro thấp.', 5, 'Doanh thu và lợi nhuận tăng trưởng mạnh, biên lợi nhuận gộp khoảng 10%. Nợ vay được kiểm soát, dòng tiền hoạt động kinh doanh dương. Công ty có đầu tư vào các công ty liên kết nhưng lỗ lũy kế. Triển vọng tích cực trong ngành logistics.'),
('VNF_2024_parent', 'VNF', 2024, 'parent', 'Công ty có nhiều giao dịch với bên liên quan, bao gồm cho vay không lãi suất (cho công ty mẹ Transimex vay 50 tỷ VNĐ với lãi suất 5.5%/năm), mua bán dịch vụ và nhận cổ tức. Các giao dịch này được thực hiện theo thỏa thuận hợp đồng, không có dấu hiệu bất thường rõ ràng về giá cả hay điều kiện.', 'Công ty chủ yếu có nợ ngắn hạn với tổng nợ phải trả là 145 tỷ VNĐ, không có nợ dài hạn. Tỷ lệ nợ trên tổng tài sản khoảng 22%, cho thấy áp lực nợ vay thấp. Tuy nhiên, nợ ngắn hạn tăng nhanh từ 97.5 tỷ lên 145 tỷ VNĐ trong năm, cần theo dõi khả năng thanh toán.', 'Hàng tồn kho có giá trị thấp (2.4 tỷ VNĐ), chiếm tỷ trọng nhỏ trong tổng tài sản. Công ty là doanh nghiệp dịch vụ logistics, nên hàng tồn kho chủ yếu là hàng hóa lưu thông, rủi ro tồn kho dở dang hay ứ đọng thấp.', 5, 'Công ty có sức khỏe tài chính ổn định với lợi nhuận sau thuế 24.9 tỷ VNĐ năm 2024, phục hồi mạnh sau khoản lỗ năm trước. Doanh thu tăng trưởng tốt, nhưng hiệu quả phụ thuộc vào hoạt động đầu tư tài chính dài hạn. Quản trị ở mức trung bình, không có rủi ro lớn. Triển vọng trung bình do cạnh tranh trong ngành logistics.'),
('VNF_2023_consolidated', 'VNF', 2023, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan bao gồm công ty mẹ, công ty con, công ty liên kết và công ty cùng tập đoàn. Các giao dịch chủ yếu là góp vốn, sử dụng dịch vụ và chia cổ tức. Mặc dù các giao dịch được thực hiện theo điều khoản thương mại, nhưng mức độ giao dịch lớn với các bên liên kết có thể tạo ra sự phụ thuộc và rủi ro về tính công bằng nếu không được giám sát chặt chẽ.', 'Công ty có nợ vay ngắn hạn từ ngân hàng với lãi suất 6.1%/năm, đáo hạn vào tháng 3 năm 2024, được đảm bảo bằng các hợp đồng tiền gửi. Nợ vay chiếm tỷ trọng nhỏ so với tổng tài sản, áp lực thanh toán thấp do có lượng tiền mặt và đầu tư ngắn hạn dồi dào.', 'Công ty không có hàng tồn kho hoặc dự án xây dựng dở dang, do hoạt động chính là cung cấp dịch vụ logistics và vận tải, nên không có rủi ro tồn kho.', 5, 'Tình hình tài chính của Vinafreight trong năm 2023 cho thấy doanh thu thuần giảm 46% và lợi nhuận sau thuế giảm 73% so với năm trước, chủ yếu do ảnh hưởng của ngành logistics hậu đại dịch. Tổng tài sản tăng nhẹ 4%, nợ vay được kiểm soát ở mức thấp. Công ty có mạng lưới đầu tư vào nhiều công ty liên kết, tạo lợi thế chiến lược nhưng cũng tiềm ẩn rủi ro quản trị. Khả năng sinh lời vẫn dương nhưng xu hướng giảm, triển vọng trung bình trong ngắn hạn.'),
('VNF_2022_consolidated', 'VNF', 2022, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm công ty mẹ, công ty liên kết và công ty trong cùng tập đoàn. Các giao dịch chủ yếu là góp vốn, mua bán dịch vụ và chi trả cổ tức. Các giao dịch này được thực hiện theo điều khoản thương mại, nhưng cần lưu ý rủi ro về tính công bằng và minh bạch trong giá cả, đặc biệt với các khoản góp vốn lớn vào công ty liên kết.', 'Nợ vay ngắn hạn của công ty rất thấp, chỉ có một khoản vay ngân hàng với lãi suất cố định. Công ty có khả năng thanh toán tốt với dòng tiền hoạt động kinh doanh dương mạnh.', 'Công ty không có hàng tồn kho do hoạt động chính trong lĩnh vực dịch vụ, nên không có rủi ro tồn kho.', 5, 'Tình hình tài chính hợp nhất của Công ty Cổ phần Vinafreight cho thấy doanh thu giảm mạnh so với năm trước, nhưng lợi nhuận vẫn dương. Công ty có cơ cấu tài sản an toàn với nợ vay thấp và dòng tiền ổn định. Tuy nhiên, sự phụ thuộc vào các giao dịch với bên liên quan và biến động trong ngành vận tải quốc tế có thể là rủi ro. Triển vọng đầu tư trung bình.'),
('VNF_2021_consolidated', 'VNF', 2021, 'consolidated', 'Nhóm Công ty có phát sinh giao dịch lớn với nhiều bên liên quan trong hệ sinh thái Transimex, bao gồm Công ty mẹ, công ty liên kết và công ty cùng tập đoàn. Đáng lưu ý: (1) Đầu tư mua trái phiếu chuyển đổi trị giá 14,87 tỷ VND từ Công ty Giao nhận Vận tải Ngoại thương (công ty liên kết) với lãi suất 7%/năm; (2) Góp vốn vào các công ty liên kết tổng cộng hơn 13,8 tỷ VND; (3) Mua dịch vụ từ các công ty cùng tập đoàn (Transimex Hi Tech Park Logistics 6 tỷ, Vận tải Transimex 3 tỷ). Tổng giá trị giao dịch với các bên liên quan trong năm vượt 69 tỷ VND. Các giao dịch này tiềm ẩn rủi ro xung đột lợi ích nếu không được thực hiện theo giá thị trường.', 'Nợ vay ngắn hạn tăng gần gấp đôi từ 123,3 tỷ lên 232,9 tỷ VND. Cả hai khoản vay đều đáo hạn rất ngắn (tháng 1-2/2022), tạo áp lực tái cấp vốn lớn ngay sau ngày lập BCTC. Lưu chuyển tiền từ hoạt động kinh doanh âm nặng (-165,8 tỷ VND), doanh nghiệp phụ thuộc lớn vào hoạt động tài chính (thuần +274,8 tỷ VND từ phát hành cổ phiếu và đi vay mới). Lãi suất ở mức hợp lý (3,0-4,8%/năm). Tài sản thế chấp gồm tiền gửi ngân hàng 10 tỷ VND.', 'Nhóm Công ty hoạt động trong lĩnh vực dịch vụ logistics, không có hàng tồn kho truyền thống (nguyên vật liệu, thành phẩm), không có xây dựng dở dang hay dự án bất động sản trên bảng cân đối kế toán. Rủi ro tồn kho không đáng kể.', 7, 'Năm 2021, Vinafreight ghi nhận tăng trưởng doanh thu ấn tượng ~99% đạt gần 4.900 tỷ VND nhờ giá cước vận tải quốc tế tăng đột biến do ảnh hưởng đại dịch Covid-19. Lợi nhuận sau thuế đạt 89,2 tỷ VND (tăng hơn 10 lần so với năm trước 8,6 tỷ). Tuy nhiên, biên lợi nhuận gộp rất mỏng (~4%), dòng tiền hoạt động kinh doanh âm nặng (-165,8 tỷ VND) phản ánh áp lực vốn lưu động lớn khi phải ứng trước cước vận tải cho hãng tàu. Công ty phụ thuộc nặng vào vay ngắn hạn có thời hạn rất ngắn. Hội đồng Quản trị có biến động lớn trong năm với 3 thành viên từ nhiệm và 2 thành viên mới. Giao dịch với bên liên quan trong hệ sinh thái Transimex rất đa dạng và có giá trị lớn, cần được giám sát chặt chẽ.'),
('VNF_2020_consolidated', 'VNF', 2020, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là giao dịch thương mại (mua bán dịch vụ vận tải, giao nhận) và chia cổ tức với các công ty mẹ, cổ đông lớn và công ty liên kết. Giá dịch vụ được thực hiện theo giá thỏa thuận, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay ngắn hạn tăng mạnh từ 89,8 tỷ VND lên 123,3 tỷ VND, nhưng được đảm bảo bằng tiền gửi và ký quỹ ngân hàng. Tỷ lệ nợ vay trên vốn chủ sở hữu khoảng 0,35, áp lực trả nợ không lớn. Công ty có khả năng thanh toán từ dòng tiền kinh doanh.', 'Không có hàng tồn kho và dự án xây dựng dở dang, nên không có rủi ro tồn kho.', 5, 'Công ty hoạt động trong lĩnh vực logistics, doanh thu tăng mạnh 62,7% nhờ tăng trưởng cước vận tải quốc tế, nhưng lợi nhuận sau thuế giảm 56,8% do chi phí dịch vụ mua ngoài và chi phí tài chính tăng. Nợ ngắn hạn tăng nhưng được kiểm soát. Công ty có mạng lưới công ty con, liên kết rộng, tập trung vào vận tải và giao nhận hàng hóa xuất nhập khẩu. Triển vọng phụ thuộc vào tình hình thương mại quốc tế và khả năng quản lý chi phí.'),
('VNF_2020_parent', 'VNF', 2020, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan bao gồm công ty con và công ty liên kết, chủ yếu là cung cấp dịch vụ, mua bán hàng hóa và vay mượn. Các giao dịch này được thực hiện theo giá thỏa thuận và không có bất thường đáng kể. Tuy nhiên, công ty có khoản vay từ công ty con Vietway với lãi suất 6%/năm, đây là mức lãi suất thị trường.', 'Công ty có nợ vay ngắn hạn và dài hạn. Nợ ngắn hạn ngân hàng được đảm bảo bằng tiền gửi có kỳ hạn và bảo lãnh của Transimex. Nợ dài hạn từ Vietway không có tài sản đảm bảo. Công ty có khả năng thanh toán nợ do dòng tiền hoạt động kinh doanh tích cực và nợ ngắn hạn đã giảm đáng kể.', 'Công ty không có hàng tồn kho và không có dự án xây dựng dở dang, do đó rủi ro tồn kho là thấp.', 5, 'Công ty hoạt động trong ngành dịch vụ logistics, có doanh thu và lợi nhuận ổn định. Tuy nhiên, công ty phụ thuộc vào các giao dịch với bên liên quan. Cơ cấu nợ đã chuyển từ ngắn hạn sang dài hạn, giảm áp lực thanh toán. Điểm rủi ro quản trị ở mức trung bình do có giao dịch với bên liên quan nhưng không có vi phạm lớn.'),
('VNF_2019_parent', 'VNF', 2019, 'parent', 'Các giao dịch với bên liên quan chủ yếu là cung cấp dịch vụ, nhận dịch vụ và chia lợi nhuận. Có một khoản vay từ công ty con (Vietway) với lãi suất 6%/năm và không có tài sản đảm bảo, tuy nhiên giá trị không quá lớn. Không phát hiện giao dịch bất thường hoặc có dấu hiệu ưu đãi quá mức.', 'Nợ ngắn hạn tăng mạnh từ 49.6 tỷ lên 69.5 tỷ VNĐ, chủ yếu do vay ngân hàng tăng. Các khoản vay ngân hàng được đảm bảo bằng tiền gửi có kỳ hạn và bảo lãnh của Công ty Cổ phần Transimex, giảm thiểu rủi ro. Công ty có đủ tiền và tương đương tiền (72.3 tỷ) để trang trải nợ ngắn hạn.', 'Công ty không có hàng tồn kho (số dư bằng 0), do đó không có rủi ro liên quan đến tồn kho dở dang hay dự án xây dựng.', 4, 'Công ty hoạt động trong lĩnh vực logistics, doanh thu và lợi nhuận sau thuế giảm so với năm trước (doanh thu giảm 14%, lợi nhuận sau thuế giảm 13%). Tuy nhiên, công ty vẫn duy trì khả năng sinh lời và có cơ cấu tài sản an toàn với tiền mặt dồi dào. Các khoản đầu tư vào công ty con và liên kết đa dạng nhưng chưa đóng góp lợi nhuận lớn. Rủi ro quản trị ở mức trung bình do có giao dịch với bên liên quan nhưng được kiểm soát.'),
('VNF_2019_consolidated', 'VNF', 2019, 'consolidated', 'Doanh nghiệp có giao dịch với nhiều bên liên quan, bao gồm cổ đông lớn và công ty liên kết. Các giao dịch được thực hiện theo giá thỏa thuận, không có dấu hiệu bất thường. Tuy nhiên, có khoản phải thu từ Công ty TNHH Chuyển phát nhanh Expo Vi Na đã được xóa sổ do công ty giải thể, cho thấy rủi ro tín dụng từ bên liên quan.', 'Nợ ngắn hạn chủ yếu từ Ngân hàng TMCP Ngoại thương Việt Nam, được đảm bảo bằng tiền gửi. Áp lực nợ vay ở mức trung bình, công ty có đủ tiền và tương đương tiền để thanh toán.', 'Không có hàng tồn kho trong báo cáo, do đó rủi ro tồn kho thấp.', 5, 'Tình hình tài chính ổn định với lợi nhuận giảm so với năm trước nhưng vẫn dương. Doanh thu chủ yếu từ dịch vụ vận tải và giao nhận. Công ty có mối quan hệ với nhiều bên liên quan nhưng không có giao dịch bất thường. Rủi ro quản trị ở mức trung bình.'),
('VNF_2017_parent', 'VNF', 2017, 'parent', 'Doanh nghiệp có nhiều giao dịch với các công ty con và công ty liên kết, bao gồm cho vay không có tài sản đảm bảo (cho Vietway vay 12 tỷ VNĐ với lãi suất 7.5%/năm). Tuy nhiên, các giao dịch này được ghi nhận và thuyết minh rõ ràng, không có dấu hiệu bất thường nổi bật.', 'Áp lực nợ vay thấp. Doanh nghiệp chỉ có một khoản vay ngắn hạn 12 tỷ VNĐ từ công ty con, thời hạn 3 tháng và không có tài sản đảm bảo. Khả năng thanh toán được đánh giá là tốt.', 'Doanh nghiệp không có hàng tồn kho và không có dự án xây dựng dở dang, do đó rủi ro tồn kho là không đáng kể.', 4, 'Công ty Cổ phần Vinafreight có sức khỏe tài chính tốt năm 2017 với lợi nhuận sau thuế tăng mạnh (79.6 tỷ VNĐ). Nợ vay thấp, thanh khoản tốt (tiền mặt và tương đương tiền đạt 46.2 tỷ VNĐ). Doanh thu chủ yếu từ dịch vụ vận tải và giao nhận. Rủi ro chính là sự phụ thuộc vào giao dịch với các bên liên quan (cổ đông lớn, công ty con, liên kết) và tỷ giá ngoại tệ, nhưng các rủi ro này được quản lý ở mức chấp nhận được. Triển vọng đầu tư tích cực trong ngắn hạn nhờ kết quả kinh doanh khả quan và kế hoạch phát hành cổ phiếu tăng vốn.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNF_2018_consolidated', 'VNF', 2018, 'consolidated', 'Tập đoàn có mạng lưới giao dịch bên liên quan phức tạp với nhiều công ty con, công ty liên kết và cổ đông lớn. Các giao dịch chủ yếu mang tính thương mại (phí vận tải, dịch vụ giao nhận) với giá thỏa thuận. Tuy nhiên, có một số điểm đáng lưu ý: (1) Khoản phải thu 1,24 tỷ VNĐ từ Công ty TNHH Chuyển phát nhanh Expo Vi Na (công ty liên kết 39%) quá hạn trên 3 năm, đã trích lập dự phòng 100%, công ty này đang trong quá trình giải thể cho thấy rủi ro mất vốn cao; (2) Trong năm trước, Tập đoàn đã cho VNT Logistics vay 6 tỷ VNĐ (không rõ lãi suất), năm nay đã thu hồi; (3) Chi phí thuê văn phòng từ Công ty Cổ phần Giao nhận Kho vận Ngoại thương Việt Nam (cổ đông lớn 10.89%) chiếm tỷ trọng đáng kể (3,47 tỷ VNĐ). Nhìn chung, các giao dịch bên liên quan chưa có dấu hiệu bất thường nghiêm trọng nhưng cần theo dõi sát khoản phải thu Expo Vi Na.', 'Tổng nợ vay ngắn hạn là 67,46 tỷ VNĐ (giảm từ 76,13 tỷ VNĐ đầu năm), toàn bộ vay từ Vietcombank - Chi nhánh TP.HCM. Nợ vay được đảm bảo bằng cầm cố tiền gửi ngân hàng với tỷ lệ tài sản đảm bảo tối thiểu 30%. Tập đoàn không có nợ dài hạn (chỉ có 5,46 tỷ VNĐ phải trả dài hạn khác). Tỷ lệ nợ vay/vốn chủ sở hữu khoảng 19,8% cho thấy đòn bẩy tài chính thấp. Tuy nhiên, toàn bộ nợ vay tập trung vào một ngân hàng (Vietcombank) tạo ra rủi ro tập trung nguồn vốn. Dòng tiền hoạt động kinh doanh năm nay chỉ đạt 19,46 tỷ VNĐ (giảm mạnh so với 106,13 tỷ VNĐ năm trước), trong khi lãi vay đã trả 4,25 tỷ VNĐ, cho thấy áp lực dòng tiền tăng lên. Khả năng thanh toán nợ vẫn đảm bảo nhờ tỷ lệ nợ thấp.', 'Tập đoàn hoạt động trong lĩnh vực dịch vụ logistics và giao nhận hàng hóa, không có hàng tồn kho trên bảng cân đối kế toán. Do đó, không có rủi ro tồn kho. Tuy nhiên, Tập đoàn có nhiều khoản đầu tư vào công ty liên kết đang trong giai đoạn đầu tư xây dựng (Cảng Mipec trị giá 157,76 tỷ VNĐ, Dịch vụ Logistics Thăng Long 29,43 tỷ VNĐ mới đi vào hoạt động cuối 2018) và Expo Vi Na đang giải thể (624 triệu VNĐ đã trích lập dự phòng toàn bộ), cần theo dõi hiệu quả của các khoản đầu tư này.', 4, 'Công ty Cổ phần Vinafreight là doanh nghiệp dịch vụ logistics hàng đầu với hơn 300 nhân viên, hoạt động chính trong vận tải hàng hóa xuất nhập khẩu và giao nhận. Báo cáo kiểm toán năm 2018 được phát hành với ý kiến chấp nhận toàn phần (unqualified). Doanh thu thuần đạt 1.667 tỷ VNĐ (giảm 11,4% so với năm trước), lợi nhuận gộp tỷ suất 3,51% (giảm so với 3,98% năm trước), lợi nhuận sau thuế đạt 33,7 tỷ VNĐ. Điểm mạnh: đòn bẩy tài chính thấp (nợ vay chỉ 67,46 tỷ VNĐ so với vốn chủ sở hữu 340,22 tỷ VNĐ), tài sản thế chấp充足 cho các khoản vay, lợi nhuận vẫn dương và có trả cổ tức. Điểm yếu: doanh thu giảm mạnh, biên lợi nhuận gộp co lại, dòng tiền hoạt động kinh doanh giảm 82% (từ 106,13 tỷ xuống 19,46 tỷ VNĐ), một khoản phải thu lớn từ công ty liên kết Expo Vi Na có nguy cơ mất trắng, và Tập đoàn phải đầu tư lớn (107,42 tỷ VNĐ) vào các công ty liên kết đang trong giai đoạn đầu tư xây dựng. Ban lãnh đạo hoạt động ổn định với Chủ tịch HĐQT kiêm Tổng Giám đốc (Ông Nguyễn Bích Lân). Triển vọng trung hạn phụ thuộc vào khả năng cải thiện biên lợi nhuận và hiệu quả từ các khoản đầu tư vào công ty liên kết.'),
('VNF_2017_consolidated', 'VNF', 2017, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là giao dịch thương mại bình thường và chia cổ tức, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Tuy nhiên, có khoản cho vay 6 tỷ VND cho VNT Logistics Jsc với lãi suất không được tiết lộ cụ thể, nhưng đã được trích lập lãi cho vay.', 'Nợ vay chủ yếu là ngắn hạn với lãi suất thả nổi, được đảm bảo bằng tiền gửi ngân hàng và phải thu khách hàng. Công ty có khả năng thanh toán tốt từ dòng tiền kinh doanh, áp lực nợ thấp.', 'Không có hàng tồn kho và dự án xây dựng dở dang, do đó không có rủi ro tồn kho.', 3, 'Công ty có kết quả kinh doanh ổn định với doanh thu tăng trưởng, biên lợi nhuận gộp khoảng 4%. Cơ cấu tài chính lành mạnh, nợ ngắn hạn có tài sản đảm bảo và dòng tiền hoạt động kinh doanh dương. Các khoản đầu tư vào công ty liên kết mang lại lợi nhuận, nhưng cần theo dõi hiệu quả của các khoản đầu tư mới. Triển vọng đầu tư trung bình khá, phù hợp với nhà đầu tư thận trọng.'),
('VNF_2016_consolidated', 'VNF', 2016, 'consolidated', 'Tập đoàn có giao dịch mua bán dịch vụ với các công ty liên kết (KWE, Vinatrans Đà Nẵng, VNT Logistics) và cổ đông lớn (Transimex, Giao nhận Kho vận Ngoại thương Việt Nam) theo giá thỏa thuận. Các giao dịch chủ yếu là doanh thu vận tải quốc tế, phí dịch vụ và chia cổ tức/lợi nhuận. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Có khoản phải thu 1.24 tỷ VND từ Expo Vi Na (công ty liên kết đang giải thể) đã trích lập dự phòng 100% do quá hạn trên 3 năm.', 'Tổng nợ vay ngắn hạn khoảng 75 tỷ VND, nợ dài hạn chỉ còn 133 triệu VND (đã kết chuyển). Lãi suất chủ yếu thả nổi theo thời kỳ. Tài sản đảm bảo bao gồm tiền gửi ngân hàng và xe ô tô. Tập đoàn trả nợ đúng hạn, không có nợ quá hạn. Tỷ lệ nợ vay/vốn chủ sở hữu thấp (khoảng 0.32), áp lực nợ vay không đáng kể. Tuy nhiên, Tập đoàn duy trì lượng lớn ký quỹ bảo lãnh cho hãng hàng không (trên 89 tỷ VND) tại nhiều ngân hàng.', 'Tập đoàn không có hàng tồn kho và không có dự án xây dựng dở dang tại ngày kết thúc năm tài chính 2016. Rủi ro tồn kho không tồn tại.', 3, 'Tập đoàn Vinafreight có tình hình tài chính ổn định với tổng tài sản 515.5 tỷ VND, vốn chủ sở hữu 235.9 tỷ VND. Lợi nhuận sau thuế đạt 44.9 tỷ VND, tăng 5.3% so với năm trước. Biên lợi nhuận gộp đạt 4.04%. Hoạt động kinh doanh chính là dịch vụ vận tải hàng hóa xuất nhập khẩu với doanh thu thuần 1,649 tỷ VND. Đầu tư vào công ty liên kết mang lại lợi nhuận đáng kể (18 tỷ VND). Dòng tiền từ hoạt động kinh doanh âm do tăng mạnh phải thu khách hàng (-42.9 tỷ VND). Công ty duy trì chính sách cổ tức ổn định (20% mệnh giá). Quản trị doanh nghiệp không có dấu hiệu bất thường lớn, các giao dịch bên liên quan minh bạch theo giá thị trường.'),
('VNF_2015_consolidated', 'VNF', 2015, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là giao dịch dịch vụ vận tải, giao nhận và chia cổ tức/dịch vụ với các cổ đông lớn và công ty liên kết. Có khoản phải thu quá hạn 3 năm từ Expo Vi Na (đang giải thể) đã trích lập dự phòng 100%. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Áp lực nợ thấp với tổng nợ vay chỉ 57.6 tỷ VND (tỷ lệ nợ/vốn chủ sở hữu ~28%). Nợ chủ yếu là ngắn hạn, được đảm bảo bằng tiền gửi ngân hàng và xe ô tô. Công ty có khả năng thanh toán tốt từ dòng tiền kinh doanh.', 'Tập đoàn không có hàng tồn kho, không có dự án bất động sản hay xây dựng dở dang lớn. Rủi ro tồn kho không đáng kể.', 3, 'Tình hình tài chính ổn định, tăng trưởng doanh thu 14.3% từ 1,702 tỷ lên 1,947 tỷ VND. Biên lợi nhuận gộp giảm nhẹ từ 3.3% xuống 3.2% do giá vốn tăng nhanh hơn doanh thu. Dòng tiền hoạt động kinh doanh âm 56.2 tỷ VND do giảm mạnh phải trả người bán, nhưng được bù đắp bởi dòng tiền từ hoạt động tài chính. Công ty có thanh khoản tốt với tiền mặt và tương đương tiền đạt 107.8 tỷ VND. Đầu tư vào công ty liên kết sinh lời tốt (18.2 tỷ VND lợi nhuận). Rủi ro thấp, triển vọng kinh doanh tích cực.'),
('VNF_2016_parent', 'VNF', 2016, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm công ty con và công ty liên kết, với giá trị lớn. Tuy nhiên, không có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất. Dự phòng nợ phải thu khó đòi đã được trích lập cho Expo Vi Na, một công ty liên kết đang giải thể.', 'Công ty không có nợ vay tài chính (vay và nợ thuê tài chính), do đó áp lực nợ vay là thấp. Các khoản phải trả chủ yếu là phải trả người bán và chi phí phải trả, với tỷ lệ nợ trên tài sản thấp, cho thấy khả năng thanh toán tốt.', 'Công ty không có hàng tồn kho do hoạt động trong lĩnh vực dịch vụ, vì vậy rủi ro tồn kho là không đáng kể.', 2, 'Công ty có tình hình tài chính ổn định với lợi nhuận sau thuế dương, vốn chủ sở hữu mạnh, và không có nợ vay tài chính. Tuy nhiên, dòng tiền từ hoạt động kinh doanh năm 2016 bị âm, cần được theo dõi. Triển vọng đầu tư phụ thuộc vào hoạt động của các công ty con và liên kết.'),
('VNF_2015_parent', 'VNF', 2015, 'parent', 'Doanh nghiệp có mạng lưới giao dịch bên liên quan phức tạp bao gồm các công ty con và công ty liên kết với nhiều giao dịch qua lại. Tổng giá trị giao dịch với các bên liên quan là rất lớn, đặc biệt là nhận lợi nhuận được chia từ công ty con Vector Aviation (15.3 tỷ VNĐ) và Vietway (2.5 tỷ VNĐ). Tuy nhiên, không có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Các giao dịch được thực hiện theo giá thỏa thuận.', 'Doanh nghiệp không có nợ vay ngân hàng hay nợ thuê tài chính. Nợ phải trả chủ yếu là phải trả người bán (12.5 tỷ), thuế và các khoản phải nộp Nhà nước (7.6 tỷ), phải trả người lao động (4.2 tỷ) và chi phí phải trả khác. Áp lực nợ thấp, công ty có khả năng thanh toán tốt từ dòng tiền hoạt động kinh doanh và tài sản ngắn hạn. Không có tài sản thế chấp.', 'Doanh nghiệp không có hàng tồn kho (giá trị ghi nhận là 0). Rủi ro tồn kho không tồn tại.', 4, 'Công ty Vinafreight có sức khỏe tài chính ổn định. Lợi nhuận sau thuế năm 2015 đạt 31.9 tỷ VNĐ (tăng nhẹ so với năm trước). Doanh thu chủ yếu từ dịch vụ giao nhận hàng hóa xuất nhập khẩu. Công ty không có nợ vay ngân hàng, thanh khoản tốt với tiền và tương đương tiền đạt 40.6 tỷ VNĐ. Tuy nhiên, công ty phụ thuộc lớn vào thu nhập từ hoạt động tài chính (chủ yếu là cổ tức từ công ty con/liên kết) và có mạng lưới giao dịch bên liên quan phức tạp. Điểm rủi ro quản trị ở mức trung bình do cơ cấu sở hữu phức tạp với nhiều cổ đông lớn và công ty con/liên kết.'),
('VND_2024_consolidated', 'VND', 2024, 'consolidated', 'Công ty có mạng lưới giao dịch bên liên quan phức tạp với nhiều công ty trong hệ sinh thái IPA. Chủ tịch HĐQT Bà Phạm Minh Hương đồng thời giữ vị trí lãnh đạo tại nhiều công ty liên quan (Quỹ IPA, IPA Holdings, IPAM LIFE, Ong Trung ương). Phó Chủ tịch HĐQT kiêm Trường ban Kiểm toán nội bộ cũng có quan hệ sở hữu chéo với nhiều công ty. Tổng giá trị mua bán chứng khoán với các bên liên quan lên đến hàng nghìn tỷ đồng (mua ~9,275 tỷ, bán ~7,993 tỷ trong năm 2024). Đặc biệt, Công ty đầu tư lớn vào trái phiếu của IPA Holdings (1,050 tỷ VND mệnh giá) và Năng lượng Bắc Hà (325 tỷ VND), tạo rủi ro tập trung tín dụng vào hệ sinh thái liên quan. Có khoản phải thu khó đòi 86 tỷ từ Công ty Năng lượng Tái tạo Trung Nam và đã trích lập dự phòng 43 tỷ. Tuy nhiên, các giao dịch này được công bố minh bạch trong báo cáo.', 'Nợ vay ngắn hạn chiếm tỷ trọng lớn (22,436 tỷ VND) với lãi suất dao động 2.0% - 7.4%/năm. Tổng nợ phải trả 24,580 tỷ VND, tương đương khoảng 1.25 lần vốn chủ sở hữu (19,715 tỷ). Trái phiếu phát hành 400 tỷ VND kỳ hạn 36 tháng lãi suất 7.58%/năm. Tài sản tài chính cầm cố đảm bảo cho vay ngắn hạn lên đến 15,049 tỷ VND. Áp lực đáo hạn nợ ngắn hạn lớn, Công ty phụ thuộc vào việc tái cấp vốn liên tục từ các ngân hàng. Tuy nhiên, Công ty có quan hệ tín dụng tốt với các ngân hàng lớn (Vietcombank, BIDV, VietinBank) và tỷ lệ nợ/vốn chủ sở hữu ở mức kiểm soát được.', 'Là công ty chứng khoán, VNDIRECT không có hàng tồn kho truyền thống. Chi phí xây dựng cơ bản dở dang chỉ 3.18 tỷ VND (không đáng kể). Rủi ro tồn kho không phải là mối lo ngại chính. Các tài sản tài chính FVTPL (24,519 tỷ) chịu rủi ro biến động thị trường chứng khoán, với mức chênh lệch giảm đánh giá lại ~7 tỷ VND trong năm.', 6, 'VNDIRECT là công ty chứng khoán lớn tại Việt Nam với vốn điều lệ 15,223 tỷ VND và tổng tài sản 44,295 tỷ VND. Năm 2024, lợi nhuận sau thuế đạt 1,718 tỷ VND (giảm 15% so với năm trước). Công ty có cơ cấu tài chính hợp lý với vốn chủ sở hữu 19,715 tỷ VND, tỷ lệ nợ/vốn chủ sở hữu ~1.25x. Điểm mạnh: đa dạng hóa hoạt động (môi giới, tự doanh, bảo lãnh phát hành), quan hệ tín dụng tốt với các ngân hàng lớn, hệ sinh thái đầu tư phong phú. Điểm cần lưu ý: (1) mạng lưới giao dịch bên liên quan phức tạp với hệ sinh thái IPA tạo rủi ro tập trung; (2) nợ vay ngắn hạn lớn đòi hỏi tái cấp vốn liên tục; (3) tài sản tài chính FVTPL chiếm tỷ trọng cao (55% tổng tài sản) tạo rủi ro biến động lợi nhuận. Kiểm toán viên Ernst & Young Việt Nam đưa ra ý kiến chấp nhận toàn phần (unqualified), không có vấn đề về hoạt động liên tục.'),
('VND_2025_consolidated', 'VND', 2025, 'consolidated', 'Công ty có mạng lưới giao dịch với bên liên quan phức tạp thuộc hệ sinh thái IPA Holdings. Các giao dịch trọng yếu bao gồm: mua hàng hóa và cung cấp dịch vụ 72,6 tỷ VNĐ; giao dịch mua chứng khoán trị giá 2.779,9 tỷ VNĐ (trong đó giao dịch với Công ty Cổ phần Tập đoàn Đầu tư I.P.A chiếm 2.450 tỷ); chuyển nhượng chứng khoán 1.561,4 tỷ VNĐ; lãi trái phiếu nhận từ bên liên quan 119,2 tỷ VNĐ. Chủ tịch HĐQT Phạm Minh Hương có mối quan hệ sở hữu chéo với nhiều công ty trong hệ sinh thái. Các khoản ký quỹ với Công ty Cổ phần Ong Trung ương lên đến 200 tỷ VNĐ. Mặc dù các giao dịch được công bố đầy đủ theo quy định, mức độ giao dịch lớn với các bên liên quan trong cùng tập đoàn đặt ra rủi ro về xung đột lợi ích và tính độc lập trong hoạt động kinh doanh.', 'Tổng nợ phải trả chiếm 59,5% tổng tài sản (30.726 tỷ VNĐ/51.629 tỷ VNĐ). Nợ ngắn hạn chiếm phần lớn cơ cấu nợ với 26.462,9 tỷ VNĐ vay ngắn hạn và 249,9 tỷ trái phiếu ngắn hạn, tạo áp lực đáo hạn lớn. Công ty đã thế chấp 17.485 tỷ VNĐ tài sản tài chính để đảm bảo cho các khoản vay ngắn hạn. Chi phí lãi vay tăng mạnh từ 667,4 tỷ lên 1.115,2 tỷ VNĐ do tăng trưởng hoạt động cho vay margin. Tuy nhiên, Công ty duy trì tỷ lệ an toàn vốn tốt với vốn chủ sở hữu 20.903 tỷ VNĐ và có quan hệ tín dụng với các ngân hàng lớn (Vietcombank, BIDV, Vietinbank). Dư nợ cho vay margin cuối năm 14.025,6 tỷ VNĐ đòi hỏi quản lý rủi ro tín dụng chặt chẽ.', 'Công ty chứng khoán VNDIRECT không có hàng tồn kho truyền thống. Chi phí xây dựng cơ bản dở dang chỉ còn 1,24 tỷ VNĐ (giảm từ 3,18 tỷ đầu năm), cho thấy không có rủi ro ứ đọng từ dự án xây dựng. Rủi ro chính liên quan đến tài sản tài chính (FVTPL 22.537,5 tỷ VNĐ) và các khoản cho vay margin (14.319,1 tỷ VNĐ) - đây là loại rủi ro đặc thù của công ty chứng khoán hơn là rủi ro tồn kho truyền thống.', 6, 'VNDIRECT là công ty chứng khoán có kết quả kinh doanh tăng trưởng tích cực năm 2025: lợi nhuận sau thuế đạt 2.022 tỷ VNĐ (tăng 17,7% so với năm trước), doanh thu hoạt động 6.640 tỷ VNĐ (tăng 24,7%). Biên lợi nhuận hoạt động tốt, lãi cơ bản trên cổ phiếu đạt 1.328 đồng/cổ phiếu (tăng từ 1.195). Vốn chủ sở hữu đạt 20.903 tỷ VNĐ, tổng tài sản 51.629 tỷ VNĐ. Công ty có hệ sinh thái kinh doanh đa dạng với môi giới, tự doanh, cho vay margin, tư vấn tài chính. Tuy nhiên, cần lưu ý: (1) Nợ ngắn hạn chiếm tỷ trọng lớn gây áp lực đáo hạn; (2) Mạng lưới giao dịch bên liên quan phức tạp trong hệ sinh thái IPA Holdings; (3) Chi phí lãi vay tăng mạnh 67% theo đà tăng trưởng cho vay. Công ty được kiểm toán bởi Ernst & Young với ý kiến chấp nhận toàn phần, không có vấn đề về hoạt động liên tục.'),
('VND_2016_consolidated', 'VND', 2016, 'consolidated', 'Công ty có giao dịch với nhiều bên liên quan, bao gồm các công ty trong tập đoàn, với các khoản đặt cọc mua công ty con và thanh toán cổ tức. Các giao dịch này có vẻ bình thường, nhưng cần theo dõi rủi ro tập trung.', 'Nợ ngắn hạn tăng mạnh, được đảm bảo bằng tiền gửi và chứng khoán, áp lực nợ vay cao với lãi suất biến động từ 2% - 7.9%/năm. Công ty duy trì tài sản đảm bảo để quản lý rủi ro thanh khoản.', 'Chi phí xây dựng cơ bản dở dang ở mức thấp, không có dự án bất động sản lớn, nên rủi ro tồn kho và dự án dở dang không đáng kể.', 5, 'Công ty chứng khoán VNDIRECT có kết quả kinh doanh tích cực với lợi nhuận tăng trưởng, nhưng nợ vay tăng nhanh có thể gây áp lực. Triển vọng phụ thuộc vào thị trường chứng khoán và quản lý rủi ro tín dụng. Điểm rủi ro quản trị ở mức trung bình do có nhiều giao dịch với bên liên quan nhưng không có dấu hiệu bất thường nghiêm trọng.'),
('VND_2015_consolidated', 'VND', 2015, 'consolidated', 'Công ty có giao dịch với các bên liên quan bao gồm chi phí thuê văn phòng, phí quản lý, thù lao cho ban lãnh đạo. Các giao dịch này có vẻ bình thường, không phát hiện bất thường rõ ràng.', 'Nợ vay tăng mạnh từ 104,945 triệu VND lên 1,600,656 triệu VND, áp lực nợ vay cao. Công ty đã phát hành trái phiếu 100 tỷ VND với lãi suất 9.2%/năm. Có tài sản đảm bảo nhưng cần theo dõi khả năng thanh toán.', 'Hàng tồn kho không có, chỉ có chi phí xây dựng cơ bản dở dang với giá trị nhỏ 543 triệu VND, rủi ro thấp.', 5, 'Công ty có tăng trưởng doanh thu và lợi nhuận tốt, nhưng nợ vay tăng nhanh. Khả năng thanh toán cần được đánh giá trong bối cảnh nợ ngắn hạn lớn.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNC_2025_consolidated', 'VNC', 2025, 'consolidated', 'Công ty có các giao dịch lớn với các công ty con (doanh thu, mua dịch vụ, phí thương hiệu) và đã trích lập dự phòng nợ phải thu khó đòi cho các khoản phải thu từ bên liên quan. Các giao dịch được thực hiện theo hợp đồng, tỷ lệ phí thương hiệu là 6,5% doanh thu. Rủi ro ở mức kiểm soát được.', 'Công ty không có các khoản vay tài chính ngắn hạn hay dài hạn trên bảng cân đối kế toán. Các khoản phải trả chủ yếu là phải trả người bán, thuế và lương nhân viên. Không có áp lực nợ vay, tình hình tài chính lành mạnh.', 'Hàng tồn kho có giá trị nhỏ (khoảng 1,3 tỷ VND) và không có dự án xây dựng dở dang. Rủi ro tồn kho thấp.', 3, 'Công ty hoạt động hiệu quả với doanh thu và lợi nhuận tăng trưởng mạnh (lợi nhuận sau thuế tăng hơn 100%). Không có nợ vay tài chính, tỷ suất lợi nhuận gộp đạt khoảng 24,5%. Dòng tiền hoạt động kinh doanh dương mạnh. Các giao dịch bên liên quan được công khai và kiểm soát. Triển vọng đầu tư tích cực.'),
('VNC_2024_consolidated', 'VNC', 2024, 'consolidated', 'Tập đoàn có giao dịch với công ty liên kết (Công ty Cổ phần Thẩm định giá Vinacontrol) và với Phó Tổng Giám đốc (ông Phan Văn Hùng) dưới hình thức tạm ứng và hoàn ứng không lãi suất, không có bảo đảm. Các giao dịch này có thể tiềm ẩn rủi ro về xung đột lợi ích hoặc thiếu minh bạch nếu không được giám sát chặt chẽ.', 'Nợ vay chủ yếu từ hợp đồng thuê tài chính với Công ty Cho thuê Tài chính TNHH BIDV-Sumi Trust (BSL), lãi suất từ 8.1% - 8.4%/năm, được thế chấp bằng máy móc, thiết bị và phương tiện vận tải. Thời gian thuê 36-48 tháng, nợ gốc trả lần cuối vào tháng 8/2027. Áp lực nợ vay ở mức vừa phải do công ty có dòng tiền từ hoạt động kinh doanh ổn định.', 'Hàng tồn kho giảm mạnh từ 6.187 tỷ VND cuối năm 2023 xuống 1.586 tỷ VND cuối năm 2024, chủ yếu do giảm nguyên vật liệu và chi phí sản xuất kinh doanh dở dang. Không có dự phòng giảm giá hàng tồn kho, cho thấy rủi ro tồn kho thấp và hàng hóa được quản lý hiệu quả.', 5, 'Tập đoàn hoạt động trong lĩnh vực giám định và phân tích, có doanh thu và lợi nhuận tăng trưởng ổn định. Nợ vay ở mức hợp lý, dòng tiền hoạt động kinh doanh dương. Tuy nhiên, giao dịch với bên liên quan cần được kiểm soát để tránh rủi ro quản trị. Triển vọng đầu tư trung bình đến tích cực do ngành dịch vụ có nhu cầu ổn định.'),
('VNC_2023_consolidated', 'VNC', 2023, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là thanh toán cổ tức, doanh thu cung cấp dịch vụ và mua dịch vụ với giá trị không lớn, không có dấu hiệu giao dịch bất thường hay giá chuyển nhượng không hợp lý.', 'Nợ vay chủ yếu là nợ thuê tài chính với tổng số tiền khoảng 1,2 tỷ VNĐ, chiếm tỷ trọng nhỏ so với tổng tài sản hơn 420 tỷ VNĐ, không có áp lực trả nợ lớn, tài sản thế chấp không được đề cập.', 'Hàng tồn kho bao gồm nguyên vật liệu và chi phí sản xuất kinh doanh dở dang, không trích lập dự phòng, cho thấy không có dấu hiệu ứ đọng hay mất giá trị nghiêm trọng.', 3, 'Công ty có tình hình tài chính lành mạnh, lợi nhuận sau thuế đạt khoảng 37,7 tỷ VNĐ, tăng trưởng doanh thu, tài sản tăng, tỷ lệ nợ thấp, dòng tiền hoạt động kinh doanh dương mạnh. Triển vọng đầu tư ổn định.'),
('VNC_2022_consolidated', 'VNC', 2022, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là giao dịch thương mại thông thường (cung cấp dịch vụ, chi trả cổ tức, mua dịch vụ) với giá trị không quá lớn so với quy mô doanh thu. Không có dấu hiệu giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Áp lực nợ vay thấp. Tổng nợ ngắn hạn và dài hạn chiếm tỷ trọng rất nhỏ trong tổng nguồn vốn (dưới 1%), chủ yếu là các khoản phải trả thông thường. Công ty có lượng tiền và tương đương tiền lớn, khả năng thanh toán nợ ngắn hạn cao. Không có tài sản thế chấp nổi bật cho các khoản vay.', 'Rủi ro tồn kho ở mức trung bình. Hàng tồn kho tăng so với đầu năm, nhưng chủ yếu là nguyên vật liệu cho hoạt động kinh doanh. Có một khoản chi phí sản xuất kinh doanh dở dang, tuy nhiên giá trị không đáng kể. Không có dự án bất động sản dở dang.', 3, 'Tập đoàn Vinacontrol thể hiện tình hình tài chính lành mạnh. Doanh thu và lợi nhuận tăng trưởng tốt. Cơ cấu vốn chủ sở hữu lớn, nợ vay rất thấp, tạo sự ổn định. Dòng tiền từ hoạt động kinh doanh dương. Các giao dịch với bên liên quan không đáng lo ngại. Công ty hoạt động trong lĩnh vực dịch vụ giám định có lịch sử và uy tín, triển vọng phát triển ổn định.'),
('VNC_2023_parent', 'VNC', 2023, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan (cổ đông lớn, công ty con, công ty liên kết) bao gồm mua bán dịch vụ, trả cổ tức, phí thương hiệu và góp vốn. Các khoản phải thu từ bên liên quan đã được trích lập dự phòng nợ khó đòi (432.4 triệu VND), cho thấy công ty có kiểm soát rủi ro. Không có dấu hiệu giao dịch bất thường rõ ràng.', 'Công ty không có nợ vay tài chính (chi phí lãi vay bằng 0). Nợ ngắn hạn chủ yếu là phải trả người bán, thuế và các khoản phải nộp nhà nước, lương nhân viên. Áp lực nợ thấp, thanh khoản tốt với tiền và tương đương tiền cuối năm đạt 72,5 tỷ VND.', 'Hàng tồn kho có giá trị nhỏ (648 triệu VND) và dự án xây dựng dở dang (300 triệu VND). Không có dự phòng giảm giá hàng tồn kho, cho thấy rủi ro ứ đọng thấp.', 2, 'Công ty có sức khỏe tài chính vững mạnh: Doanh thu tăng trưởng 11.8% (từ 326.6 tỷ lên 365.1 tỷ VND), lợi nhuận sau thuế tăng nhẹ 0.8%. Không sử dụng nợ vay, dòng tiền từ hoạt động kinh doanh dương mạnh (35.3 tỷ VND). Công ty duy trì tỷ suất lợi nhuận gộp ổn định (khoảng 21.2%). Tuy nhiên, doanh thu phụ thuộc lớn vào công ty con (Giám định Vinacontrol HCM). Triển vọng đầu tư tích cực nhờ hoạt động kinh doanh chính tăng trưởng, quản trị tài chính thận trọng và thanh khoản dồi dào.'),
('VNC_2022_parent', 'VNC', 2022, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan, đặc biệt là công ty con và công ty liên kết, bao gồm doanh thu, mua dịch vụ, phí thương hiệu và chia lợi nhuận. Các giao dịch được thực hiện theo thỏa thuận, không có lãi suất, nhưng quy mô lớn có thể tiềm ẩn rủi ro về xung đột lợi ích nếu không được quản lý chặt chẽ.', 'Công ty không có nợ vay tại thời điểm cuối năm, nhưng có chi phí lãi vay phát sinh trong năm cho thấy có hoạt động vay mượn. Tuy nhiên, với vốn chủ sở hữu mạnh và dòng tiền từ hoạt động kinh doanh dương, rủi ro nợ vay thấp.', 'Hàng tồn kho chủ yếu là công cụ, dụng cụ với giá trị nhỏ, không có dự án xây dựng dở dang, nên rủi ro tồn kho thấp.', 4, 'Tập đoàn Vinacontrol có kết quả kinh doanh tích cực với doanh thu và lợi nhuận tăng trưởng, biên lợi nhuận gộp ổn định. Vốn chủ sở hữu tăng mạnh, không có nợ vay dài hạn. Tuy nhiên, cần theo dõi các giao dịch với bên liên quan để đảm bảo tính minh bạch. Triển vọng đầu tư trung bình đến tích cực.'),
('VNC_2021_consolidated', 'VNC', 2021, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là thanh toán cổ tức và cung cấp dịch vụ, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Rủi ro thấp.', 'Công ty có nợ vay với lãi suất hợp lý và tài sản thế chấp đầy đủ. Áp lực nợ vay không quá cao nhờ dòng tiền kinh doanh ổn định và tài sản đảm bảo.', 'Hàng tồn kho chủ yếu là nguyên vật liệu và công cụ, giá trị không lớn và không có dự phòng giảm giá, rủi ro tồn kho thấp.', 3, 'Tập đoàn Vinacontrol có tình hình tài chính ổn định với doanh thu và lợi nhuận tăng trưởng. Biên lợi nhuận gộp ở mức khá, nợ vay được kiểm soát và tài sản thế chấp đầy đủ. Quản trị doanh nghiệp minh bạch, giao dịch với bên liên quan đơn giản. Triển vọng đầu tư tích cực trong trung hạn.'),
('VNC_2021_parent', 'VNC', 2021, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan bao gồm cổ đông lớn, công ty con và công ty liên kết. Các giao dịch chủ yếu là cung cấp và mua dịch vụ, chi trả cổ tức, và phí sử dụng thương hiệu. Năm nay không có giao dịch cho vay không lãi suất bất thường. Rủi ro ở mức thấp do các giao dịch được thực hiện theo thỏa thuận và không có dấu hiệu bất thường.', 'Công ty có nợ vay tổng cộng khoảng 10,2 tỷ VNĐ, trong đó nợ ngắn hạn là phần đến hạn của nợ dài hạn. Nợ dài hạn từ một ngân hàng với lãi suất 7.6%/năm và có tài sản thế chấp là quyền sử dụng đất và tài sản hình thành từ dự án. Áp lực nợ vay không quá cao do tỷ lệ nợ trên tổng tài sản thấp (khoảng 3.3%) và khả năng thanh toán ổn định.', 'Hàng tồn kho chủ yếu là nguyên liệu và công cụ, dụng cụ với giá trị nhỏ (khoảng 711 triệu VNĐ) và không có dự phòng giảm giá. Dự án xây dựng dở dang liên quan đến phần mềm kế toán và dự án khác, chưa có dấu hiệu ứ đọng. Rủi ro tồn kho thấp.', 3, 'Công ty có tình hình tài chính lành mạnh với doanh thu thuần tăng nhẹ, lợi nhuận sau thuế đạt 32.5 tỷ VNĐ. Tỷ suất lợi nhuận gộp khoảng 24.8%, dòng tiền từ hoạt động kinh doanh dương. Nợ vay được kiểm soát, tài sản thế chấp đầy đủ. Công ty có lịch sử chia cổ tức ổn định. Triển vọng đầu tư tích cực nhờ vào hoạt động kinh doanh cốt lõi là giám định và phân tích mẫu có nhu cầu ổn định.'),
('VNC_2020_parent', 'VNC', 2020, 'parent', 'Công ty có các giao dịch với công ty con, công ty liên kết và cổ đông lớn. Đáng chú ý là khoản cho vay không lãi suất 500 triệu VND cho Công ty Cổ phần Tư vấn và Thẩm định Môi trường Vinacontrol (công ty con). Các giao dịch mua bán dịch vụ, phí thương hiệu và chia lợi nhuận với công ty con là hoạt động kinh doanh bình thường trong tập đoàn, tuy nhiên việc cho vay không lãi suất tiềm ẩn rủi ro về hiệu quả sử dụng vốn và quản trị công ty.', 'Nợ vay chủ yếu là vay dài hạn từ ngân hàng Vietcombank với lãi suất cố định 7.6%/năm, được đảm bảo bằng quyền sử dụng đất và tài sản hình thành từ dự án đầu tư. Tổng nợ vay khoảng 12.3 tỷ VND, chiếm tỷ lệ nhỏ trong tổng tài sản (khoảng 4.3%). Áp lực trả nợ không cao do nợ được phân kỳ trả gốc hàng quý.', 'Hàng tồn kho có giá trị nhỏ (473 triệu VND), chủ yếu là nguyên vật liệu, không có dự phòng giảm giá. Dự án phần mềm kế toán đang trong quá trình triển khai, không có dấu hiệu ứ đọng hay chậm tiến độ đáng kể.', 4, 'Công ty có sức khỏe tài chính ổn định với biên lợi nhuận gộp cao (khoảng 27.85%), hoạt động kinh doanh chính (giám định, phân tích mẫu) tạo dòng tiền tốt. Nợ vay có mức độ rủi ro thấp do có tài sản đảm bảo và lịch trả nợ rõ ràng. Tuy nhiên, cần theo dõi các giao dịch với bên liên quan, đặc biệt là khoản cho vay không lãi suất cho công ty con. Công ty duy trì chính sách cổ tức ổn định, trả cổ tức đều đặn hàng năm.'),
('VNC_2020_consolidated', 'VNC', 2020, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là chi trả cổ tức cho cổ đông lớn và giao dịch dịch vụ với công ty liên kết. Giá trị giao dịch không đáng kể so với quy mô doanh nghiệp, không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay chủ yếu là vay ngân hàng dài hạn với lãi suất cố định và được thế chấp bằng tài sản. Công ty có dòng tiền kinh doanh dương, khả năng thanh toán tốt. Tuy nhiên, có khoản vay cá nhân không lãi suất, nhưng giá trị nhỏ.', 'Hàng tồn kho giảm so với đầu năm, không có dự phòng giảm giá. Dự án xây dựng dở dang là dự án phần mềm, không có dấu hiệu ứ đọng, rủi ro thấp.', 3, 'Công ty hoạt động ổn định trong lĩnh vực giám định và phân tích. Doanh thu và lợi nhuận tăng trưởng nhẹ. Tình hình tài chính lành mạnh, thanh khoản tốt, nợ vay có tài sản đảm bảo. Ban lãnh đạo minh bạch, kiểm toán độc lập. Triển vọng đầu tư tích cực.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNC_2019_consolidated', 'VNC', 2019, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu bao gồm thanh toán cổ tức, doanh thu cung cấp dịch vụ và một khoản vay không lãi suất từ thành viên Ban Kiểm soát. Không phát hiện giao dịch bất thường hoặc có rủi ro đáng kể.', 'Công ty có nợ vay ngắn hạn và dài hạn với tổng giá trị khoảng 18.6 tỷ VNĐ, được đảm bảo bằng tài sản như quyền sử dụng đất và xe ô tô. Áp lực nợ vay ở mức trung bình, khả năng thanh toán được hỗ trợ bởi dòng tiền từ hoạt động kinh doanh ổn định.', 'Hàng tồn kho bao gồm nguyên vật liệu, công cụ dụng cụ và chi phí sản xuất dở dang với tổng giá trị khoảng 4.3 tỷ VNĐ, không có dự phòng giảm giá. Rủi ro tồn kho thấp do giá trị nhỏ và không có dấu hiệu ứ đọng.', 2, 'Tập đoàn Vinacontrol có tình hình tài chính ổn định với doanh thu và lợi nhuận tăng trưởng nhẹ. Biên lợi nhuận gộp khoảng 23.5%, nợ vay được kiểm soát và tài sản thế chấp đầy đủ. Dòng tiền hoạt động kinh doanh mạnh, đủ để tài trợ cho đầu tư và trả nợ. Rủi ro quản trị thấp do cấu trúc sở hữu rõ ràng và giao dịch bên liên quan minh bạch.'),
('VNC_2019_parent', 'VNC', 2019, 'parent', 'Công ty có giao dịch đáng kể với các bên liên quan, bao gồm doanh thu từ dịch vụ và phí thương hiệu với công ty con. Các giao dịch được thực hiện theo hợp đồng và không có lãi suất, nhưng cần theo dõi để đảm bảo tính minh bạch.', 'Nợ vay chủ yếu từ ngân hàng với tài sản thế chấp là bất động sản và quyền sử dụng đất. Áp lực nợ trung bình với lãi suất cố định, khả năng thanh toán ổn định.', 'Tồn kho thấp, chủ yếu là nguyên vật liệu. Các dự án xây dựng dở dang đã hoàn thành hoặc giá trị nhỏ, rủi ro tồn kho không đáng kể.', 5, 'Công ty có doanh thu và lợi nhuận tăng trưởng ổn định, tỷ suất lợi nhuận gộp cao. Nợ vay được kiểm soát, tài sản thế chấp đầy đủ. Tuy nhiên, cần quan tâm đến giao dịch với bên liên quan và quản lý dòng tiền.'),
('VNC_2018_parent', 'VNC', 2018, 'parent', 'Công ty có giao dịch đáng kể với các bên liên quan, đặc biệt là phí sử dụng thương hiệu 18,86 tỷ VND và doanh thu dịch vụ 4,32 tỷ VND từ Công ty TNHH Giám định Vinacontrol TP.HCM (công ty con). Các khoản phải thu từ công ty con lên đến 15,5 tỷ VND (phải thu khác) và 2,85 tỷ VND (phải thu khách hàng). Số dư phải thu, phải trả với bên liên quan không có lãi suất, không bảo đảm và không trích lập dự phòng nợ khó đòi. Tổng Công ty Đầu tư và Kinh doanh vốn Nhà nước (cổ đông lớn 30%) nhận cổ tức 4,725 tỷ VND. Nhìn chung, giao dịch với bên liên quan diễn ra thường xuyên với quy mô lớn nhưng trong khuôn khổ hoạt động kinh doanh chính, chưa có dấu hiệu bất thường rõ ràng.', 'Tổng nợ vay cuối năm 22,58 tỷ VND (tăng mạnh từ 11,3 tỷ VND đầu năm), trong đó nợ ngắn hạn 5,14 tỷ VND và nợ dài hạn 17,45 tỷ VND. Nợ vay được đảm bảo bằng quyền sử dụng đất và tài sản gắn liền. Lãi suất vay dao động 7,6%-9,5%/năm, chi phí lãi vay năm 2018 là 1,54 tỷ VND. Áp lực trả nợ gốc và lãi hàng tháng/quý. Tuy nhiên, tỷ lệ nợ/vốn chủ sở hữu khoảng 0,27 cho thấy mức đòn bẩy tài chính còn thấp, lợi nhuận trước thuế 38 tỷ VND đủ sức chi trả chi phí lãi vay.', 'Hàng tồn kho thông thường chỉ 390 triệu VND, không đáng kể. Tuy nhiên, chi phí xây dựng cơ bản dở dang lên đến 18,37 tỷ VND, tăng mạnh 217% so với đầu năm. Dự án lớn nhất là Trung tâm Phân tích và Thử nghiệm 1 tại Ninh Hiệp chiếm 16,75 tỷ VND, được tài trợ bởi khoản vay dài hạn đáo hạn năm 2026. Rủi ro chính là tiến độ triển khai dự án và hiệu quả đầu tư. Dự án phần mềm kế toán 1,4 tỷ VND vẫn giữ nguyên, chưa có tiến triển.', 5, 'Công ty Cổ phần Tập đoàn Vinacontrol có tình hình tài chính ổn định với doanh thu tăng 13,3% (270 tỷ VND), lợi nhuận sau thuế tăng 3,7% (33,8 tỷ VND). Biên lợi nhuận gộp đạt 29,4%. Công ty có cổ đông lớn là Tổng Công ty Đầu tư và Kinh doanh vốn Nhà nước (30% vốn). Ban lãnh đạo kiêm nhiệm giữa công ty mẹ và các công ty con. Công ty đang trong giai đoạn mở rộng đầu tư với dự án Trung tâm Phân tích tại Ninh Hiệp quy mô lớn. Các khoản đầu tư vào công ty con và liên kết được ghi theo giá gốc (62,6 tỷ VND). Dự phòng phải thu khó đòi tăng 23% so với năm trước. Công ty trả cổ tức đều đặn (tổng 15,75 tỷ VND năm 2018). Triển vọng đầu tư ở mức trung bình khá.'),
('VNC_2018_consolidated', 'VNC', 2018, 'consolidated', 'Các giao dịch với bên liên quan bao gồm chi trả cổ tức cho cổ đông lớn (Tổng Công ty Đầu tư và Kinh doanh vốn Nhà nước), doanh thu dịch vụ và lợi nhuận được chia từ các công ty liên kết (Văn phòng Công chứng Thăng Long, Công ty Cổ phần Thẩm định giá Vinacontrol). Các giao dịch được thực hiện theo thỏa thuận hợp đồng, không có lãi suất và không có bảo đảm. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn với bên liên quan.', 'Tổng nợ vay là 23,78 tỷ VND, trong đó vay ngắn hạn 6,34 tỷ VND và vay dài hạn 17,45 tỷ VND. Các khoản vay ngân hàng có tài sản thế chấp là quyền sử dụng đất và tài sản gắn liền. Dòng tiền kinh doanh thuần đạt 31,5 tỷ VND, đủ để trả lãi vay. Khoản vay cá nhân không lãi suất đáo hạn vào tháng 6/2019 có thể gây áp lực thanh toán ngắn hạn.', 'Hàng tồn kho giảm nhẹ và không có dự phòng giảm giá. Các dự án xây dựng dở dang tăng mạnh từ 5,79 tỷ lên 18,37 tỷ VND, tập trung vào dự án Trung tâm Phân tích và Thử nghiệm 1 tại Ninh Hiệp. Cần theo dõi tiến độ và khả năng hoàn thành của dự án này.', 5, 'Tập đoàn Vinacontrol ghi nhận tăng trưởng doanh thu 8% và lợi nhuận sau thuế tăng 3.6% trong năm 2018. Tỷ suất lợi nhuận gộp đạt khoảng 22%. Dòng tiền kinh doanh thuần dương, đáp ứng được nghĩa vụ nợ. Công ty đang đầu tư mạnh vào dự án Trung tâm Phân tích và Thử nghiệm 1 tại Ninh Hiệp, cần theo dõi tiến độ. Rủi ro tài chính ở mức kiểm soát, tuy nhiên áp lực nợ ngắn hạn cần được quản lý.'),
('VNC_2016_consolidated', 'VNC', 2016, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là thanh toán cổ tức cho các cổ đông lớn và quỹ đầu tư, cùng thù lao cho ban lãnh đạo. Không có thông tin về các giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn với công ty con hay công ty sân sau.', 'Áp lực nợ vay ở mức trung bình. Tổng nợ vay (ngắn và dài hạn) khoảng 16,19 tỷ VNĐ, trong đó nợ dài hạn chiếm phần lớn (12.59 tỷ VNĐ) với lãi suất từ 6% đến 11.7%. Các khoản vay ngân hàng được đảm bảo bằng tài sản cố định có giá trị còn lại 14,463 triệu VNĐ. Nợ cá nhân không có tài sản đảm bảo.', 'Rủi ro tồn kho thấp. Hàng tồn kho chủ yếu là nguyên vật liệu (3.12 tỷ VNĐ) và công cụ dụng cụ nhỏ. Chi phí sản xuất kinh doanh dở dang đã được kết chuyển vào giá vốn. Các dự án xây dựng dở dang có quy mô nhỏ và đã được xử lý trong năm (xóa số hoặc chuyển sang TSCĐ).', 5, 'Tập đoàn Vinacontrol có kết quả kinh doanh tăng trưởng tốt trong năm 2016 với lợi nhuận sau thuế tăng 18% so với năm trước. Cơ cấu tài sản lành mạnh, chủ yếu là tài sản cố định phục vụ kinh doanh. Nợ vay có tài sản đảm bảo, khả năng thanh toán ổn định. Các giao dịch với bên liên quan không có dấu hiệu bất thường. Tuy nhiên, công ty đang có một số khoản đầu tư vào công ty liên kết với giá trị ghi sổ giảm và một số dự án xây dựng dở dang đã được xóa sổ, cho thấy một số hoạt động đầu tư chưa hiệu quả. Tình hình tài chính chung là an toàn và triển vọng kinh doanh tích cực.'),
('VNC_2017_consolidated', 'VNC', 2017, 'consolidated', 'Doanh nghiệp có giao dịch lớn với các bên liên quan, đặc biệt với công ty con Công ty TNHH Giám định Vinacontrol TP. Hồ Chí Minh (doanh thu dịch vụ 12,5 tỷ VNĐ, phí tư vấn 17,4 tỷ VNĐ, cổ tức 14,8 tỷ VNĐ). Các khoản phải thu từ bên liên quan không tính lãi và có thể yêu cầu thanh toán khi có nhu cầu, tạo rủi ro về dòng tiền. Tổng phải thu ngắn hạn từ bên liên quan khoảng 3,8 tỷ VNĐ. Mặc dù các giao dịch được thuyết minh đầy đủ, mức độ tập trung doanh thu vào công ty con là đáng lưu ý.', 'Tổng nợ vay khoảng 11,3 tỷ VNĐ, chiếm tỷ trọng nhỏ trong tổng tài sản (237,9 tỷ VNĐ). Các khoản vay ngân hàng được đảm bảo bằng tài sản cố định hữu hình có giá trị còn lại 13,5 tỷ VNĐ, tỷ lệ che phủ nợ vay tốt. Lãi suất dao động 6-7.6%/năm ở mức hợp lý. Áp lực trả nợ ngắn hạn (5,2 tỷ VNĐ) có thể kiểm soát được nhờ dòng tiền kinh doanh dồi dào (17,6 tỷ VNĐ tiền thuần từ hoạt động kinh doanh).', 'Hàng tồn kho ở mức thấp (395 triệu VNĐ), chủ yếu là nguyên vật liệu và công cụ dụng cụ, không có rủi ro ứ đọng lớn. Tuy nhiên, xây dựng cơ bản dở dang tăng mạnh từ 65 triệu lên 5,8 tỷ VNĐ với 3 dự án đang triển khai, trong đó dự án Trung tâm Phân tích tại Ninh Hiệp chiếm 3,6 tỷ VNĐ. Các dự án này cần được theo dõi tiến độ và hiệu quả đầu tư.', 3, 'Công ty Cổ phần Tập đoàn Vinacontrol có sức khỏe tài chính ổn định với doanh thu thuần tăng trưởng 3.9% (từ 229,3 tỷ lên 238,2 tỷ VNĐ) và lợi nhuận sau thuế tăng 8.4% (từ 30,1 tỷ lên 32,6 tỷ VNĐ) trong năm 2017. Biên lợi nhuận gộp đạt 31.8%, phản ánh năng lực sinh lời tốt trong ngành dịch vụ giám định. Nợ vay thấp, tài sản thế chấp che phủ tốt. Dòng tiền hoạt động kinh doanh dương mạnh (17,6 tỷ VNĐ). Công ty có hệ thống công ty con và liên kết tạo chuỗi giá trị trong ngành giám định - chứng nhận - thẩm định. Rủi ro chính là tập trung doanh thu vào công ty con lớn và các dự án xây dựng dở dang cần được giám sát tiến độ. Đơn vị kiểm toán KPMG đưa ra ý kiến chấp nhận toàn phần, tăng cường độ tin cậy của báo cáo tài chính.'),
('VNB_2025_consolidated', 'VNB', 2025, 'consolidated', 'Công ty có giao dịch đáng kể với các bên liên quan trong Tập đoàn Vingroup, đặc biệt là Công ty Cổ phần In Sách Việt Nam (công ty liên kết) với doanh thu cho thuê nhà và chi phí in sách. Giao dịch với Công ty Cổ phần Đầu tư Cam Ranh liên quan đến khoản cho vay lớn (100 tỷ VND tiền gốc thu hồi). Các giao dịch này theo thỏa thuận hợp đồng, không có lãi suất và không cần bảo đảm, nhưng cần theo dõi tính công bằng về giá và rủi ro thanh toán.', 'Áp lực nợ vay thấp. Công ty chủ yếu có nợ ngắn hạn phát sinh từ hoạt động kinh doanh thông thường (phải trả người bán, thuế). Nợ dài hạn chỉ có 468 triệu VND. Tuy nhiên, thuế và các khoản phải nộp Nhà nước chiếm tỷ trọng lớn (21 tỷ VND). Công ty có khoản cho vay dài hạn 1,008 tỷ VND với lãi suất 12%/năm đáo hạn tháng 1/2027, tạo nguồn thu nhập tài chính ổn định.', 'Hàng tồn kho có dự phòng giảm giá 2.67 tỷ VND, tăng so với năm trước. Thành phẩm chiếm tỷ trọng lớn (9.9 tỷ VND). Dự án xây dựng dở dang (22A Hai Bà Trưng) trị giá 6 tỷ VND đã treo nguyên giá từ năm trước, chưa có tiến triển, có thể ứ đọng vốn.', 4, 'Sức khỏe tài chính của công ty khá tốt với lợi nhuận sau thuế tăng 10.6% so với năm trước. Công ty có tỷ suất lợi nhuận gộp cao (42.5%), chủ yếu nhờ hoạt động cho thuê bất động sản đầu tư. Tuy nhiên, doanh thu từ kinh doanh sách giảm. Công ty có cơ cấu tài sản an toàn với nợ vay thấp, nhưng phụ thuộc lớn vào doanh thu tài chính (lãi cho vay và tiền gửi). Quản trị công ty minh bạch với Ban Kiểm soát và Ban Tổng Giám đốc rõ ràng, nhưng có mối quan hệ phức tạp trong Tập đoàn Vingroup.'),
('VNC_2016_parent', 'VNC', 2016, 'parent', 'Giao dịch với các bên liên quan chủ yếu là doanh thu dịch vụ, cổ tức, góp vốn và thu hồi vốn, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Áp lực nợ vay ở mức trung bình, tổng nợ vay không quá cao so với vốn chủ sở hữu, các khoản vay ngân hàng được đảm bảo bằng tài sản cố định hữu hình, lãi suất hợp lý.', 'Tồn kho có giá trị nhỏ và chủ yếu là nguyên vật liệu và công cụ, dự án xây dựng dở dang giảm đáng kể và có giá trị thấp, rủi ro tồn kho và dự án thấp.', 2, 'Công ty có tình hình tài chính lành mạnh, lợi nhuận thuần tăng trưởng qua các năm, khả năng thanh toán tốt với tỷ lệ nợ trên vốn hợp lý, hoạt động kinh doanh chính tạo ra doanh thu ổn định và lợi nhuận gộp cao. Quản trị công ty minh bạch với các giao dịch bên liên quan rõ ràng.'),
('VNC_2015_consolidated', 'VNC', 2015, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là trả cổ tức và lương thưởng cho ban lãnh đạo, không có giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Tuy nhiên, có giao dịch điều chuyển Công ty CP Thẩm định giá Vinacontrol (công ty liên kết) với giá trị tài sản giảm và đầu tư tăng, cần theo dõi.', 'Nợ vay tăng mạnh từ 841 triệu lên 17,6 tỷ VNĐ, chủ yếu do vay ngân hàng 3 (14,7 tỷ đáo hạn 2020). Áp lực nợ vay tăng nhưng được đảm bảo bằng tài sản cố định hữu hình trị giá 15,4 tỷ. Lãi suất từ 6% đến 11,7%.', 'Hàng tồn kho giảm từ 4,3 tỷ xuống 2,7 tỷ, chủ yếu do nguyên vật liệu giảm. Chi phí xây dựng dở dang tăng nhẹ nhưng không có dấu hiệu ứ đọng lớn.', 3, 'Công ty có doanh thu và lợi nhuận tăng trưởng tốt trong năm 2015. Nợ vay tăng đáng kể để tài trợ đầu tư tài sản cố định, nhưng có tài sản đảm bảo. Dòng tiền kinh doanh mạnh, thanh khoản tốt. Rủi ro quản trị ở mức thấp.'),
('VNB_2023_consolidated', 'VNB', 2023, 'consolidated', 'Công ty có giao dịch với các bên liên quan (công ty cùng tập đoàn Vingroup và công ty liên kết In Sách Việt Nam) bao gồm doanh thu bán hàng, cho thuê nhà và chi phí in ấn. Các giao dịch diễn ra theo giá thỏa thuận, không có dấu hiệu bất thường rõ rệt về giá hay điều kiện. Số dư phải thu với các bên liên quan không trích lập dự phòng, tuy nhiên giá trị không quá lớn so với tổng tài sản.', 'Nợ vay ngắn hạn lớn (827 tỷ VNĐ) phát sinh từ hoạt động cho vay của Công ty, với lãi suất 11-12%/năm và được đảm bảo bằng vốn góp. Công ty chủ yếu là bên cho vay, không phải đi vay. Nợ phải trả thương mại chủ yếu với Cambridge University Press và các nhà xuất bản khác, không có áp lực nợ vay ngân hàng hay nợ dài hạn lớn.', 'Hàng tồn kho tăng nhẹ, chủ yếu là thành phẩm và hàng hóa kinh doanh sách. Dự phòng giảm giá tồn kho được trích lập hợp lý. Dự án xây dựng dở dang (22A Hai Bà Trưng) đã có chi phí bồi thường 6 tỷ VNĐ, chưa rõ tiến độ triển khai.', 3, 'Sức khỏe tài chính của Công ty ổn định với lợi nhuận sau thuế tăng 72% so với cùng kỳ, chủ yếu nhờ doanh thu hoạt động tài chính tăng mạnh. Cơ cấu tài sản chủ yếu là các khoản đầu tư tài chính ngắn hạn và phải thu cho vay. Công ty có vị thế tiền mặt tốt và không có nợ vay ngân hàng. Tuy nhiên, doanh thu từ hoạt động kinh doanh chính (bán sách và cho thuê) tăng trưởng chậm. Rủi ro quản trị ở mức thấp do giao dịch bên liên quan minh bạch và không phức tạp.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNC_2015_parent', 'VNC', 2015, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan, đặc biệt là công ty con và công ty liên kết, tập trung vào doanh thu dịch vụ, phí tư vấn và chia cổ tức. Các khoản phải thu từ bên liên quan không có lãi suất và có thể yêu cầu thanh toán khi có nhu cầu. Không phát hiện giao dịch bất thường lớn như cho vay không lãi suất hay mua bán chênh lệch giá.', 'Công ty có nợ vay dài hạn với lãi suất cố định, đáo hạn xa (2017-2020), được đảm bảo bằng tài sản cố định. Áp lực thanh toán nợ ngắn hạn thấp do chủ yếu là nợ dài hạn. Tuy nhiên, công ty đã gia tăng vay nợ trong năm 2015 để đầu tư tài sản cố định.', 'Hàng tồn kho chủ yếu là nguyên vật liệu và công cụ dụng cụ với giá trị nhỏ. Công trình xây dựng dở dang chiếm tỷ trọng nhỏ và không có thông tin về ứ đọng hay chậm tiến độ. Rủi ro tồn kho thấp.', 3, 'Công ty có kết quả kinh doanh tăng trưởng tốt, lợi nhuận thuần tăng 5.5% so với năm trước, tỷ suất lợi nhuận gộp đạt 28.4%. Nợ vay được kiểm soát với tài sản thế chấp đầy đủ. Dòng tiền từ hoạt động kinh doanh dương nhưng giảm so với năm trước. Công ty có giao dịch với nhiều bên liên quan nhưng không có dấu hiệu bất thường. Triển vọng đầu tư ổn định.'),
('VNB_2024_consolidated', 'VNB', 2024, 'consolidated', 'Công ty có quan hệ mật thiết với Tập đoàn Vingroup (công ty mẹ) và thực hiện nhiều giao dịch với các bên liên quan trong tập đoàn, bao gồm cho vay có lãi suất 12%/năm với Công ty CP Đầu tư Cam Ranh, cho thuê nhà với Công ty CP In Sách Việt Nam (công ty liên kết). Các giao dịch được thực hiện theo mức giá thỏa thuận hợp đồng và chưa trích lập dự phòng nợ phải thu khó đòi. Cần theo dõi chặt chẽ các khoản cho vay lớn với bên liên quan.', 'Áp lực nợ vay thấp do công ty chủ yếu có nợ phải trả thương mại và thuế, không có nợ vay ngân hàng lớn. Tổng nợ phải trả 28,4 tỷ VND, trong đó nợ ngắn hạn chiếm 27,8 tỷ VND. Công ty có tài sản lớn (1.130,7 tỷ VND) và tỷ lệ nợ trên tài sản thấp (khoảng 2,5%). Tuy nhiên, khoản thuế phải nộp tăng đáng kể (19,3 tỷ VND).', 'Hàng tồn kho có dự phòng giảm giá 1,986 tỷ VND trên giá gốc 11,3 tỷ VND (tỷ lệ dự phòng ~17,5%). Hàng tồn kho chủ yếu là hàng hóa và thành phẩm sách, có thể bị lỗi thời hoặc giảm giá. Dự án xây dựng cơ bản dở dang (22A Hai Bà Trung) trị giá 6 tỷ VND là chi phí giải phóng mặt bằng, chưa triển khai xây dựng, tiềm ẩn rủi ro về tiến độ và khả năng thu hồi vốn.', 5, 'Công ty Cổ phần Sách Việt Nam có kết quả kinh doanh ổn định với lợi nhuận sau thuế 75,1 tỷ VND năm 2024 (tăng 9,1% so với năm trước). Doanh thu giảm nhẹ do mảng bán sách sụt giảm nhưng được bù đắp bởi doanh thu cho thuê bất động sản tăng. Công ty có sức khỏe tài chính tốt với tỷ suất lợi nhuận gộp cao (41,5%), không có nợ vay ngân hàng, và lượng tiền mặt cùng đầu tư ngắn hạn dồi dào. Tuy nhiên, công ty chịu rủi ro từ hợp đồng thuê đất có thể hết hạn và dự án bất động sản chưa triển khai. Giao dịch với các bên liên quan trong tập đoàn Vingroup cần được giám sát để đảm bảo tính minh bạch.'),
('VNB_2022_consolidated', 'VNB', 2022, 'consolidated', 'Giao dịch với bên liên quan (Công ty Cổ phần In Sách Việt Nam) bao gồm cho thuê nhà và in sách. Các giao dịch này được thực hiện theo giá thỏa thuận và không có lãi suất, chưa có dự phòng nợ phải thu khó đòi. Rủi ro ở mức trung bình, không có dấu hiệu giao dịch bất thường.', 'Áp lực nợ vay thấp. Tổng nợ phải trả (18.276 tỷ VND) chiếm tỷ lệ nhỏ so với tổng tài sản (976.681 tỷ VND). Nợ ngắn hạn chủ yếu là phải trả người bán và thuế. Nợ dài hạn (478 triệu VND) không đáng kể. Công ty có tài sản thế chấp là bất động sản đầu tư lớn.', 'Rủi ro tồn kho ở mức thấp. Hàng tồn kho chủ yếu là sách (hàng hóa và thành phẩm) với dự phòng giảm giá được trích lập hợp lý. Dự án xây dựng dở dang (6 tỷ VND) là chi phí bồi thường giải phóng mặt bằng, chưa có dấu hiệu ứ đọng.', 3, 'Sức khỏe tài chính của Công ty Sách Việt Nam rất tốt với tốc độ tăng trưởng lợi nhuận sau thuế 22% (từ 32.744 tỷ lên 40.002 tỷ VND). Công ty có tỷ suất lợi nhuận gộp cao (khoảng 41%), doanh thu tăng mạnh 46% nhờ tăng trưởng cả mảng bán sách và cho thuê bất động sản đầu tư. Công ty có cơ cấu tài sản an toàn, nợ phải trả thấp, và dòng tiền hoạt động kinh doanh bị âm do cho vay lớn nhưng được bù đắp bằng thu nhập tài chính. Triển vọng đầu tư tích cực nhờ vào vị thế thị trường và tài sản bất động sản đầu tư giá trị.'),
('VNB_2020_consolidated', 'VNB', 2020, 'consolidated', 'Công ty có phát sinh doanh thu từ cho thuê nhà, chi phí in ấn và nhận cổ tức với công ty liên kết (In Sách Việt Nam) và doanh thu bán hàng cho các công ty cùng tập đoàn (Vinschool, VinAcademy). Các giao dịch được thực hiện theo thỏa thuận giá thị trường, không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn bất thường. Rủi ro từ giao dịch bên liên quan ở mức thấp.', 'Công ty không có nợ vay ngân hàng (chi phí lãi vay bằng 0). Các khoản nợ chủ yếu là phải trả người bán và thuế, mang tính chất lưu động của hoạt động kinh doanh. Nợ dài hạn rất nhỏ (238 tỷ VND) và là ''phải trả dài hạn khác'' không rõ chi tiết. Áp lực nợ vay là không đáng kể, khả năng thanh toán tốt.', 'Tồn kho chủ yếu là hàng hóa và thành phẩm (sách), có trích lập dự phòng giảm giá ~1 tỷ VND. Dự án xây dựng dở dang là chi phí bồi thường giải phóng mặt bằng cho dự án bất động sản tại 22A Hai Bà Trưng, trị giá 6 tỷ VND. Không có thông tin về tiến độ dự án này, nên rủi ro ứ đọng vốn ở mức trung bình.', 4, 'Công ty kinh doanh trong lĩnh vực sách và cho thuê bất động sản. Năm 2020, doanh thu giảm nhẹ (~6%) nhưng lợi nhuận sau thuế giảm mạnh (~58%) chủ yếu do sụt giảm lớn từ doanh thu hoạt động tài chính (giảm 54%). Công ty có nền tảng tài sản vững chắc (tổng tài sản ~898 tỷ VND), không có nợ vay và dòng tiền kinh doanh âm nhưng bù đắp bằng dòng tiền đầu tư. Rủi ro chính là sự phụ thuộc vào hoạt động cho thuê bất động sản và rủi ro từ dự án bất động sản dở dang. Sức khỏe tài chính cơ bản lành mạnh, triển vọng phụ thuộc vào khả năng hồi phục của mảng bán lẻ sách và tiến độ dự án bất động sản.'),
('VNB_2019_consolidated', 'VNB', 2019, 'consolidated', 'Công ty có giao dịch với nhiều bên liên quan, bao gồm công ty liên kết (In Sách) và các công ty cùng tập đoàn (Vinschool, Vincommerce, VinAcademy). Các giao dịch chủ yếu là thương mại (cho thuê nhà, bán hàng, mua dịch vụ in ấn) theo giá thỏa thuận, thanh toán bằng tiền và không có lãi suất. Không thấy giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn bất thường.', 'Công ty không có nợ vay tài chính (chi phí lãi vay bằng 0). Các khoản nợ phải trả chủ yếu là phải trả người bán và thuế, mang tính chất kinh doanh thường xuyên. Áp lực nợ vay không đáng kể. Các khoản cho vay ngắn hạn lớn (550 tỷ) là nguồn tài chính cho đối tác, không phải là nợ của công ty.', 'Hàng tồn kho chủ yếu là thành phẩm và hàng hóa. Dự án xây dựng dở dang (6 tỷ) là chi phí đền bù giải phóng mặt bằng, chưa triển khai xây dựng và không có dấu hiệu ứ đọng. Công ty đã trích lập dự phòng giảm giá hàng hóa hơn 1,16 tỷ, cho thấy có sự thận trọng trong đánh giá giá trị tồn kho.', 4, 'Công ty có tình hình tài chính lành mạnh, không có nợ vay, lợi nhuận tăng trưởng mạnh (174%) nhờ thu nhập tài chính lớn từ thanh lý đầu tư và lãi cho vay. Tuy nhiên, lợi nhuận hoạt động kinh doanh cốt lõi (bán sách, cho thuê) tăng không đáng kể. Dòng tiền hoạt động kinh doanh âm do cho vay và đầu tư lớn. Rủi ro主要集中于 tính thanh khoản của khoản phải thu ngắn hạn rất lớn từ hoạt động cho vay và các cam kết đất đai chưa được cấp hợp đồng thuê dài hạn.'),
('VNB_2021_consolidated', 'VNB', 2021, 'consolidated', 'Công ty có các giao dịch với bên liên quan như cho thuê nhà, bán hàng và chia cổ tức. Các giao dịch được thực hiện theo thỏa thuận hợp đồng, không có lãi suất hay tài sản thế chấp, rủi ro thấp.', 'Công ty không có nợ vay tài chính lớn, nợ chủ yếu là phải trả người bán và thuế, áp lực nợ thấp.', 'Hàng tồn kho có dự phòng giảm giá, và có dự án xây dựng dở dang, rủi ro tồn kho ở mức trung bình.', 3, 'Lợi nhuận giảm 13% so với năm trước do ảnh hưởng của đại dịch Covid-19, nhưng công ty vẫn duy trì hoạt động có lãi. Tài sản lớn, tập trung vào bất động sản đầu tư và cho thuê. Quản trị rủi ro ở mức an toàn.'),
('VNB_2018_consolidated', 'VNB', 2018, 'consolidated', 'Doanh nghiệp có giao dịch lớn với các công ty cùng Tập đoàn Vingroup, đặc biệt khoản cho vay tín chấp 550 tỷ VNĐ với lãi suất 9%/năm cho Công ty Sinh Thái (cùng Tập đoàn). Doanh thu từ bên liên quan chiếm khoảng 14% tổng doanh thu (5,1 tỷ/36,8 tỷ). Các khoản phải thu từ bên liên quan (In Sách Việt Nam) lên tới 3,9 tỷ VNĐ. Rủi ro ở mức trung bình do giao dịch tập trung trong nội bộ Tập đoàn.', 'Áp lực nợ vay thấp vì Công ty không có nợ vay ngân hàng. Nợ chủ yếu là phải trả thương mại cho nhà cung cấp (8,35 tỷ) và đặt cọc thuê văn phòng (493 triệu). Công ty có khoản cho vay lớn 550 tỷ VNĐ (tương đương 71% tổng tài sản) nhưng đây là tài sản chứ không phải nợ phải trả. Tổng nợ phải trả chỉ chiếm 2,2% tổng tài sản (17 tỷ/775 tỷ).', 'Hàng tồn kho tăng từ 7,3 tỷ lên 9,3 tỷ VNĐ (tăng 26%). Dự án 22A Hai Bà Trưng trị giá 6 tỷ đã tồn tại ít nhất 2 năm không thay đổi, cho thấy dự án có thể bị đình trệ hoặc chờ phê duyệt. Tuy nhiên, tổng giá trị tồn kho và dự án không đáng kể so với tổng tài sản (2% tổng tài sản).', 5, 'Savina là doanh nghiệp hoạt động trong lĩnh vực kinh doanh sách và cho thuê bất động sản đầu tư, thuộc hệ sinh thái Vingroup. Sức khỏe tài chính tương đối tốt với tỷ suất lợi nhuận gộp 32,6%, không có nợ vay ngân hàng, và tổng nợ phải trả rất thấp (2,2% tổng tài sản). Doanh thu tăng trưởng 18%, lợi nhuận sau thuế tăng 20%. Tuy nhiên, dòng tiền hoạt động kinh doanh âm (-25 tỷ) do phải thu tăng mạnh. Công ty có khoản đầu tư tài chính lớn (cho vay 550 tỷ, đầu tư dài hạn 9,4 tỷ) tạo ra thu nhập tài chính đáng kể (53,5 tỷ). Điểm cần lưu ý: giao dịch với bên liên quan lớn, khoản cho vay tín chấp 550 tỷ cho công ty cùng Tập đoàn, và dự án bất động sản 22A Hai Bà Trưng bị đình trệ.'),
('VNB_2016_consolidated', 'VNB', 2016, 'consolidated', 'Công ty có giao dịch lớn với các bên liên quan, đáng chú ý là khoản cho vay 600 tỷ VNĐ cho Công ty Cổ phần Đầu tư và Phát triển Sinh Thái (cùng Tập đoàn) với lãi suất 7%/năm và không có tài sản đảm bảo. Đây là giao dịch có rủi ro cao do số tiền lớn và không có bảo đảm. Ngoài ra, doanh thu cho thuê nhà từ Công ty liên kết (In Sách Việt Nam) là 1,5 tỷ VNĐ.', 'Nợ phải trả chủ yếu là nợ ngắn hạn (khoảng 58,5 tỷ VNĐ) bao gồm chi phí phải trả, thuế phải nộp và các khoản phải trả khác. Công ty không có nợ vay dài hạn lớn. Tuy nhiên, áp lực nợ ngắn hạn ở mức trung bình cao.', 'Hàng tồn kho giảm từ 7,6 tỷ xuống 4,6 tỷ VNĐ và không trích lập dự phòng. Chi phí xây dựng cơ bản dở dang 4,5 tỷ VNĐ liên quan đến giải phóng mặt bằng có thể bị ứ đọng do chưa hoàn tất thủ tục đất đai.', 7, 'Công ty ghi nhận lợi nhuận sau thuế 8,88 tỷ VNĐ trong giai đoạn từ 27/4/2016 đến 31/12/2016, chủ yếu từ hoạt động kinh doanh sách và cho thuê bất động sản. Tuy nhiên, doanh nghiệp đối mặt với nhiều rủi ro: (1) Giao dịch lớn với bên liên quan không có tài sản đảm bảo, (2) Nhiều tồn đọng tài chính từ thời kỳ trước cổ phần hóa được xử lý vào lỗ lũy kế, (3) Kiểm toán viên đưa ra ý kiến ngoại trừ do không xác định được giá trị hàng tồn kho và chiết khấu sách. Triển vọng đầu tư phụ thuộc vào việc xử lý các vấn đề đất đai và quản trị công ty.'),
('VNB_2017_consolidated', 'VNB', 2017, 'consolidated', 'Công ty có giao dịch lớn với các công ty cùng Tập đoàn Vingroup. Đáng chú ý nhất là khoản cho vay 600 tỷ VNĐ không có tài sản đảm bảo cho Công ty CP Đầu tư và Phát triển Sinh Thái với lãi suất 7%/năm (khoản vay đã được thu hồi toàn bộ trong năm 2017). Công ty cũng có quan hệ kinh doanh với Công ty liên kết In Sách Việt Nam (35% vốn) với doanh thu cho thuê nhà đất và chi phí in sách. Doanh thu từ các bên liên quan chiếm khoảng 15% tổng doanh thu. Các giao dịch được thực hiện theo giá thỏa thuận, không có dự phòng nợ phải thu khó đòi.', 'Công ty không có nợ vay ngân hàng hay nợ tài chính, chủ yếu là nợ thương mại và nghĩa vụ thuế. Tổng nợ phải trả giảm mạnh từ 59,2 tỷ xuống 22,7 tỷ VNĐ (-62%). Tuy nhiên, khoản phải trả cổ phần hóa 7,6 tỷ VNĐ theo Quyết định 891/QĐ-BVHTTDL là nghĩa vụ phát sinh từ quá trình chuyển đổi. Công ty có tỷ lệ nợ/vốn chủ sở hữu rất thấp (3,1%), phản ánh tình hình tài chính an toàn về đòn bẩy.', 'Hàng tồn kho tăng từ 4,5 tỷ lên 7,3 tỷ VNĐ (+60%), phản ánh hoạt động kinh doanh sách mở rộng. Dự án xây dựng dở dang 22A Hai Bà Trưng trị giá 6 tỷ VNĐ là chi phí giải phóng mặt bằng, chưa rõ tiến độ triển khai thực tế. Một rủi ro đáng kể là ý kiến kiểm toán ngoại trừ liên quan đến giá trị hàng tồn kho tại thời điểm cổ phần hóa (27/4/2016), do hệ thống sổ sách kế toán cũ có hạn chế trong việc xác định chiết khấu và hàng ký gửi.', 7, 'Công ty Cổ phần Sách Việt Nam ghi nhận kết quả kinh doanh tích cực năm 2017 với lợi nhuận sau thuế 27,3 tỷ VNĐ (tăng 207% so với giai đoạn 2016 không trọn năm). Tuy nhiên, chất lượng lợi nhuận đáng lo ngại vì doanh thu hoạt động tài chính chiếm tỷ trọng rất lớn (42,3 tỷ VNĐ, chủ yếu từ lãi cho vay 37,5 tỷ), trong khi lợi nhuận gộp từ hoạt động kinh doanh cốt lõi chỉ 5,6 tỷ VNĐ (biên gộp 18%). Công ty có ý kiến kiểm toán ngoại trừ do hạn chế trong kiểm toán hàng tồn kho tại thời điểm cổ phần hóa. Điểm rủi ro quản trị ở mức 7/10 do có giao dịch lớn với công ty cùng Tập đoàn (cho vay 600 tỷ không tài sản đảm bảo), rủi ro về hợp đồng thuê đất chưa gia hạn, và các khoản nợ tiềm tàng liên quan đến vốn góp đất tại Công ty Liên doanh TNHH Kim Ngọc.'),
('VNB_2015_consolidated', 'VNB', 2015, 'consolidated', 'Công ty có giao dịch với công ty liên kết Công ty CP In Sách Việt Nam, bao gồm doanh thu bán hàng và khoản phải thu. Không có dấu hiệu bất thường lớn về giá hay điều kiện giao dịch, nhưng cần giám sát chặt chẽ mối quan hệ này.', 'Công ty không có nợ vay ngân hàng, nợ chủ yếu là phải trả người bán và chi phí phải trả với tổng giá trị lớn. Áp lực thanh toán ngắn hạn cao, nhưng không phát sinh lãi suất vay, giảm rủi ro tài chính.', 'Hàng tồn kho ổn định và không trích lập dự phòng. Tuy nhiên, kiểm toán viên không thể xác minh đầy đủ hàng tồn kho do thời điểm kiểm toán, đặt ra rủi ro về tính hiện hữu và giá trị.', 6, 'Công ty có biên lợi nhuận gộp cao (khoảng 50.6%), nhưng lợi nhuận ròng thấp do chi phí bán hàng và quản lý doanh nghiệp lớn. Tình hình tài chính ổn định với lượng tiền mặt lớn từ tiền gửi ngân hàng. Đang trong quá trình cổ phần hóa và chuyển đổi mô hình. Kiểm toán có ngoại trừ về hàng tồn kho và công nợ, ảnh hưởng đến độ tin cậy của báo cáo tài chính. Triển vọng phụ thuộc vào việc cổ phần hóa thành công và cải thiện hiệu quả quản lý.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNA_2025_consolidated', 'VNA', 2025, 'consolidated', 'Công ty có phát sinh giao dịch kinh doanh đáng kể với các bên liên quan thuộc cùng tập đoàn (cổ đông lớn - Tổng Công ty Hàng hải Việt Nam và các công ty liên quan). Tổng doanh thu từ các bên liên quan chiếm khoảng 4.3% doanh thu thuần (26.254 tỷ/610.099 tỷ). Các giao dịch chủ yếu là dịch vụ logistics, bốc xếp, cho thuê cảng. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn rõ ràng. Rủi ro tập trung vào sự phụ thuộc vào các mối quan hệ trong tập đoàn.', 'Công ty tăng cường vay nợ để đầu tư đội tàu mới (tỷ lệ 60% vốn vay). Tổng nợ vay tăng mạnh từ 146.337 tỷ (01/2025) lên 276.360 tỷ (31/12/2025). Áp lực trả nợ lãi vay tăng đáng kể (chi phí lãi vay 2025: 10.399 tỷ, năm 2024: 782 tỷ). Tuy nhiên, phần lớn nợ vay dài hạn có tài sản thế chấp là tàu biển mới mua. Cần theo dõi sát khả năng dòng tiền hoạt động kinh doanh (23.355 tỷ năm 2025) trang trải chi phí lãi vay và nợ gốc đến hạn.', 'Hàng tồn kho chủ yếu là nguyên nhiên liệu cho hoạt động vận tải (36.033 tỷ) và chi phí sản xuất kinh doanh dở dang (2.850 tỷ). Giá trị tồn kho giảm nhẹ so với đầu năm. Rủi ro tồn kho không cao do đây là vật tư tiêu hao cho dịch vụ vận tải, không phải hàng hóa bất động sản hay dự án xây dựng dở dang có khả năng ứ đọng.', 5, 'Công ty đang trong giai đoạn mở rộng, trẻ hóa đội tàu thông qua vay nợ lớn. Kết quả kinh doanh năm 2025 giảm do chi phí tài chính tăng vọt, nhưng lợi nhuận gộp cải thiện. Dòng tiền kinh doanh vẫn dương nhưng không đủ bù đắp chi phí đầu tư lớn. Sức khỏe tài chính bị ảnh hưởng bởi đòn bẩy nợ cao. Triển vọng phụ thuộc vào hiệu quả khai thác đội tàu mới và diễn biến thị trường vận tải biển.'),
('VNA_2025_parent', 'VNA', 2025, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan trong tập đoàn, bao gồm công ty mẹ và các công ty con. Các giao dịch này chủ yếu là mua bán hàng hóa dịch vụ và cho thuê, với giá trị không quá lớn so với quy mô doanh thu. Tuy nhiên, cần lưu ý khoản phải thu từ Công ty TNHH MTV Vận tải viễn dương Vinashin đã được trích lập dự phòng 100%, cho thấy rủi ro thu hồi.', 'Tổng nợ vay tài chính tăng mạnh từ 146.337.500.000 VNĐ đầu năm lên 276.360.342.856 VNĐ cuối năm, chủ yếu do vay dài hạn để đầu tư tàu mới. Áp lực nợ vay tăng lên, nhưng Công ty có tài sản cố định thế chấp và dòng tiền từ hoạt động kinh doanh dương.', 'Hàng tồn kho và chi phí xây dựng cơ bản dở dang có giá trị tương đối ổn định. Không có dấu hiệu ứ đọng lớn.', 6, 'Công ty có lợi nhuận sau thuế giảm từ 65,36 tỷ xuống 42,85 tỷ VNĐ, do chi phí tài chính tăng mạnh do vay mua tàu mới. Doanh thu giảm nhẹ nhưng giá vốn giảm nhiều hơn, cải thiện biên lợi nhuận gộp. Công ty đang trong quá trình trẻ hóa đội tàu, làm tăng đòn bẩy tài chính. Dòng tiền từ hoạt động kinh doanh vẫn dương, đảm bảo khả năng thanh toán nợ. Rủi ro quản trị ở mức trung bình do giao dịch bên liên quan và tăng trưởng nợ.'),
('VNA_2024_parent', 'VNA', 2024, 'parent', 'Giao dịch với bên liên quan có giá trị tương đối nhỏ và chủ yếu là mua bán dịch vụ hàng hải, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty vay nợ dài hạn từ Ngân hàng TMCP Hàng Hải Việt Nam để mua tàu mới, tài sản thế chấp là tàu Vinaship Unity. Áp lực nợ vay đáng kể với tổng nợ 146.337.500.000 VNĐ, lãi suất cố định ban đầu sau đó thả nổi, nhưng công ty có dòng tiền từ hoạt động kinh doanh.', 'Hàng tồn kho tăng chủ yếu do nguyên liệu vật liệu, không có dự phòng giảm giá, rủi ro thấp.', 5, 'Công ty đạt lợi nhuận sau thuế cao trong năm 2024 chủ yếu từ thanh lý tàu cũ và đầu tư tàu mới, cải thiện hiệu quả khai thác. Tuy nhiên, lợi nhuận gộp từ hoạt động vận tải biển vẫn thấp, cho thấy biên lợi nhuận mỏng. Công ty đã tăng vốn chủ sở hữu và vay nợ để mở rộng, nhưng cần theo dõi áp lực nợ vay và khả năng sinh lời từ hoạt động chính.'),
('VNA_2024_consolidated', 'VNA', 2024, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là giao dịch mua bán hàng hóa, dịch vụ trong hoạt động kinh doanh bình thường, không có dấu hiệu bất thường về giá cả hay điều kiện thanh toán.', 'Nợ vay chủ yếu để đầu tư mua tàu mới, có tài sản thế chấp là tàu, lãi suất cố định trong 2 năm đầu, áp lực trả nợ trung bình.', 'Hàng tồn kho chủ yếu là nguyên liệu và chi phí sản xuất dở dang, không có dự phòng giảm giá, rủi ro thấp.', 3, 'Công ty có sự tăng trưởng lợi nhuận mạnh trong năm 2024 nhờ hoạt động thanh lý tàu cũ và đầu tư tàu mới. Cơ cấu tài chính cải thiện với việc tăng vốn chủ sở hữu và vay vốn đầu tư. Triển vọng kinh doanh tích cực trong trung hạn.'),
('VNA_2023_parent', 'VNA', 2023, 'parent', 'Giao dịch với bên liên quan chủ yếu là doanh thu dịch vụ và phải trả ngắn hạn với công ty mẹ. Số tiền không lớn so với tổng tài sản, nhưng cần theo dõi giao dịch với công ty mẹ và công ty con để đảm bảo tính minh bạch.', 'Công ty đã trả hết nợ vay ngân hàng, áp lực nợ thấp. Tuy nhiên, còn nợ lãi phải trả cho Ngân hàng Phát triển Việt Nam và có lịch sử nợ tái cơ cấu.', 'Hàng tồn kho giảm đáng kể, chủ yếu là nguyên vật liệu. Dự án xây dựng dở dang đang triển khai, có thể ảnh hưởng dòng tiền và cần theo dõi tiến độ.', 3, 'Công ty có tình hình tài chính ổn định với lợi nhuận sau thuế 35.4 tỷ VNĐ, nợ vay bằng không, và dòng tiền từ hoạt động kinh doanh dương. Tuy nhiên, doanh thu giảm so với năm trước do ngành vận tải biển khó khăn, cần cải thiện hiệu quả kinh doanh và quản lý tài sản.'),
('VNA_2022_parent', 'VNA', 2022, 'parent', 'Công ty có giao dịch lớn với Công ty TNHH Mua bán nợ Việt Nam (DATC) liên quan đến tái cơ cấu khoản vay với các ngân hàng. Công ty đã hoàn thành trả nợ cho DATC khoản nợ tái cơ cấu với Ngân hàng TNHH Indovina và tiếp tục đàm phán tái cơ cấu khoản vay với Ngân hàng TMCP Bảo Việt. Công ty con 100% là Công ty TNHH Dịch vụ Hàng hải Vinaship hoạt động trong lĩnh vực dịch vụ bốc xếp hàng hóa và logistics. Không phát hiện giao dịch bất thường với bên liên quan như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Tổng nợ vay giảm mạnh từ 314,7 tỷ VNĐ (01/01/2022) xuống còn 36,0 tỷ VNĐ (31/12/2022), phản ánh nỗ lực tái cơ cấu nợ thành công. Công ty đã thanh toán toàn bộ nợ với DATC và Ngân hàng TMCP Bảo Việt. Nợ vay còn lại chủ yếu từ Ngân hàng Phát triển Việt Nam với lãi suất thả nổi, được thế chấp bằng các tàu biển. Tiền mặt và tương đương tiền đạt 237,4 tỷ VNĐ, khả năng thanh toán nợ ngắn hạn cao.', 'Hàng tồn kho giảm từ 78,8 tỷ VNĐ xuống 58,2 tỷ VNĐ, trong đó chi phí SXKD dở dang giảm mạnh từ 35,0 tỷ xuống 10,3 tỷ VNĐ cho thấy hoạt động vận tải biển diễn ra thuận lợi, hàng hóa lưu thông nhanh. Dự án xây dựng trụ sở văn phòng mới đang triển khai với tổng mức đầu tư dự kiến 80,97 tỷ đồng, dự kiến hoàn thành năm 2024, chưa có dấu hiệu ứ đọng.', 4, 'Năm 2022, Công ty ghi nhận kết quả kinh doanh ấn tượng với doanh thu thuần 1.005,7 tỷ VNĐ (tăng 30,7% so với năm trước), biên lợi nhuận gộp 27,37%. Lợi nhuận sau thuế đạt 251,0 tỷ VNĐ. Thành công lớn nhất là việc tái cơ cấu nợ vay thành công, giảm nợ vay từ 314,7 tỷ xuống 36,0 tỷ VNĐ, đồng thời ghi nhận thu nhập từ tái cơ cấu 61,4 tỷ VNĐ. Công ty thanh lý tàu Mỹ Thịnh theo kế hoạch, ghi nhận thu nhập 47,2 tỷ VNĐ. Thanh khoản tốt với tiền mặt 237,4 tỷ VNĐ. Triển vọng tích cực nhờ ngành vận tải biển thuận lợi với giá cước duy trì ở mức cao.'),
('VNA_2022_consolidated', 'VNA', 2022, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là giao dịch kinh doanh thông thường với công ty mẹ và các công ty cùng tập đoàn, không có dấu hiệu bất thường.', 'Công ty đang tái cơ cấu nợ với DATC và các ngân hàng, có tài sản thế chấp là tàu biển, nhưng vẫn có nợ tồn đọng.', 'Hàng tồn kho bao gồm nguyên liệu và chi phí sản xuất dở dang, nhưng không có dự phòng giảm giá, rủi ro trung bình.', 5, 'Công ty có sự tăng trưởng mạnh về lợi nhuận trong năm 2022, nợ vay giảm đáng kể do thanh lý tàu và tái cơ cấu nợ. Tuy nhiên, vẫn còn nợ với DATC và ngân hàng. Triển vọng tích cực trong ngắn hạn.'),
('VNA_2021_parent', 'VNA', 2021, 'parent', 'Không có giao dịch với bên liên quan đáng kể được ghi nhận trong báo cáo. Công ty có đầu tư vào công ty con là Công ty TNHH Dịch vụ Hàng hải Vinaship với tỷ lệ sở hữu 100%, nhưng không phát sinh giao dịch mua bán lớn bất thường.', 'Công ty có nợ ngắn hạn vượt quá tài sản ngắn hạn 31,65 tỷ đồng, lỗ lũy kế 41,25 tỷ đồng. Nợ vay ngân hàng lớn, đang trong quá trình tái cơ cấu nợ với Công ty TNHH Mua bán nợ Việt Nam (DATC). Áp lực nợ vay cao, tài sản thế chấp chủ yếu là tàu biển.', 'Hàng tồn kho là nguyên liệu, vật liệu tăng từ 36,069,394,090 lên 43,318,914,139 VND, không có dự phòng giảm giá. Các dự án xây dựng dở dang có quy mô nhỏ, chưa có dấu hiệu ứ đọng.', 5, 'Công ty đã có năm 2021 kinh doanh hiệu quả với doanh thu thuần 804,603,456,700 VND và lợi nhuận sau thuế 177,311,341,167 VND, do thị trường vận tải biển thuận lợi. Tuy nhiên, vẫn còn lỗ lũy kế và nợ ngắn hạn cao, khả năng hoạt động liên tục phụ thuộc vào quá trình tái cơ cấu nợ. Triển vọng trung hạn tích cực nếu thị trường vận tải biển duy trì và tái cơ cấu nợ thành công.'),
('VNA_2021_consolidated', 'VNA', 2021, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan trong tập đoàn Vinalines (công ty mẹ và các công ty cùng tập đoàn). Đặc biệt, có khoản vay cá nhân với các thành viên HĐQT và Ban Tổng Giám đốc tổng cộng 2,15 tỷ đồng (đã giảm từ 7,97 tỷ đầu năm), lãi suất 10%/năm - mức lãi suất hợp lý. Doanh thu từ bên liên quan chiếm tỷ trọng nhỏ (~0,5% doanh thu). Không phát hiện giao dịch bất thường hay có dấu hiệu chuyển giá với bên liên quan.', 'Công ty đang trong quá trình tái cơ cấu nợ theo chỉ đạo của Chính phủ giai đoạn 2017-2020. Nợ ngắn hạn vượt tài sản ngắn hạn 26,6 tỷ đồng. Có khoản nợ gốc và lãi vay với IVB Mỹ Đình hơn 106 tỷ đồng đang chờ xử lý, đã chuyển sang DATC mua lại. Nợ quá hạn với ngân hàng Bảo Việt hơn 55,8 tỷ đồng gốc và 20,5 tỷ đồng lãi. Công ty đã ký cọc 20 tỷ đồng cho DATC. Áp lực nợ vay rất lớn với tổng nợ phải trả 471,6 tỷ đồng, trong đó nợ vay chiếm 211,9 tỷ đồng.', 'Tồn kho chủ yếu là nguyên liệu, vật liệu phục vụ vận tải biển (43,3 tỷ đồng), tăng so với đầu năm. Dự án xây dựng dở dang 1,03 tỷ đồng bao gồm dự án bãi Container và trụ sở văn phòng mới - dự án trụ sở mới đang trong giai đoạn xin cấp phép xây dựng, có thể chậm tiến độ so với kế hoạch hoàn thành tháng 01/2023. Rủi ro tồn kho ở mức thấp do tính chất ngành vận tải biển.', 6, 'Công ty vận tải biển Vinaship có sự phục hồi mạnh mẽ trong năm 2021 nhờ lợi thế từ thị trường vận tải biển thuận lợi, doanh thu tăng 66% đạt 853 tỷ đồng và có lãi 177,8 tỷ đồng (so với lãi chỉ 1,3 tỷ năm 2020). Tuy nhiên, Công ty vẫn đối mặt với rủi ro lớn về khả năng hoạt động liên tục do: (1) Nợ ngắn hạn vượt tài sản ngắn hạn; (2) Lỗ lũy kế 40,6 tỷ đồng; (3) Áp lực tái cơ cấu nợ lớn với nhiều khoản vay quá hạn; (4) Phụ thuộc vào kết quả đàm phán với DATC và các ngân hàng. Điểm tích cực là dòng tiền hoạt động kinh doanh dương mạnh 224,9 tỷ đồng, cho thấy Công ty có khả năng tạo tiền mặt tốt. Triển vọng phụ thuộc vào diễn biến thị trường vận tải biển và tiến trình tái cơ cấu nợ.'),
('VMT_2025_consolidated', 'VMT', 2025, 'consolidated', 'Công ty có nhiều giao dịch với công ty mẹ (Transimex) và các công ty trong cùng Tập đoàn, bao gồm doanh thu, mua dịch vụ và vay nợ. Giá trị giao dịch mua dịch vụ với Transimex khá lớn (hơn 3,5 tỷ đồng). Tuy nhiên, lãi suất vay từ công ty mẹ (7%/năm) là hợp lý và không có dấu hiệu bất thường rõ ràng.', 'Áp lực nợ vay đã giảm đáng kể so với năm trước nhờ tăng vốn chủ sở hữu thông qua phát hành cổ phiếu. Nợ vay chủ yếu từ ngân hàng Shinhan có tài sản thế chấp là bất động sản, và nợ từ công ty mẹ không có tài sản thế chấp nhưng lãi suất cố định. Tổng nợ ngắn hạn và dài hạn vẫn ở mức cao nhưng đã giảm một nửa so với năm trước.', 'Hàng tồn kho giá trị nhỏ (25 triệu đồng) không đáng lo ngại. Dự án xây dựng dở dang (Tòa nhà 49 Phan Đăng Lưu) đang trong giai đoạn lập hồ sơ, chưa có rủi ro ứ đọng vốn lớn.', 4, 'Công ty đã tăng vốn thành công để giảm áp lực nợ vay, cải thiện cơ cấu tài chính. Doanh thu và lợi nhuận tăng trưởng nhẹ. Tuy nhiên, công ty vẫn phụ thuộc vào giao dịch với tập đoàn mẹ và các công ty liên kết. Điểm mạnh là dòng tiền kinh doanh dương, tài sản có giá trị và hoạt động kinh doanh cốt lõi ổn định.');
PRAGMA foreign_keys = ON;
